{
  "name": "MedTrack AI",
  "description": "A smart medication tracker that allows users to log pills as they happen, aggregate ingredient dosages, and use AI to manage their logs."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Ingredient {
  name: string;
  dosageMg: number;
}

export interface Pill {
  id: string;
  name: string;
  ingredients: Ingredient[]; // Max 3
  color: string;
}

export interface LogEntry {
  id: string;
  timestamp: number;
  pillIds: string[]; // Max 3
  notes?: string;
}

export interface UserData {
  email: string;
  pills: Pill[];
  logs: LogEntry[];
}

export interface DailyAggregation {
  date: string; // YYYY-MM-DD
  logs: LogEntry[];
  totalIngredients: Record<string, number>; // Ingredient Name -> Total Mg
}

export enum AppTab {
  DASHBOARD = 'dashboard',
  CABINET = 'cabinet',
  ASSISTANT = 'assistant',
}

import { UserData, Pill, LogEntry } from '../types';

const STORAGE_KEY_PREFIX = 'medtrack_user_';

export const loadUserData = (email: string): UserData => {
  const key = `${STORAGE_KEY_PREFIX}${email.toLowerCase().trim()}`;
  const stored = localStorage.getItem(key);
  if (stored) {
    return JSON.parse(stored);
  }
  return {
    email,
    pills: [],
    logs: [],
  };
};

export const saveUserData = (data: UserData) => {
  const key = `${STORAGE_KEY_PREFIX}${data.email.toLowerCase().trim()}`;
  localStorage.setItem(key, JSON.stringify(data));
};

export const generateId = () => Math.random().toString(36).substring(2, 9);

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Pill, LogEntry } from '../types';

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Parses a natural language string to suggest a log entry.
 */
export const parseNaturalLanguageLog = async (
  input: string,
  availablePills: Pill[]
): Promise<{ pillIds: string[], notes: string, confidence: string } | null> => {
  const ai = getAI();

  const pillMap = availablePills.map(p => ({ id: p.id, name: p.name })).map(p => `${p.name} (ID: ${p.id})`).join(', ');

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      pillIds: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "List of Pill IDs extracted from the text. Match closely to available pills."
      },
      notes: {
        type: Type.STRING,
        description: "Any extra context mentioned (e.g., 'after dinner', 'headache')."
      },
      confidence: {
        type: Type.STRING,
        enum: ["HIGH", "LOW"],
        description: "Confidence level of the match."
      }
    },
    required: ["pillIds", "confidence"]
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `User Input: "${input}". 
      Available Pills: [${pillMap}].
      Task: Extract the pills taken. If a pill name roughly matches an available pill, include its ID. Max 3 pills.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      }
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    return null;
  } catch (e) {
    console.error("AI Parse Error", e);
    return null;
  }
};

/**
 * Answers questions about the user's log history.
 */
export const analyzeHistory = async (
  query: string,
  logs: LogEntry[],
  pills: Pill[]
): Promise<string> => {
  const ai = getAI();

  // Create a minified text representation of the data to fit context
  const pillLookup = new Map(pills.map(p => [p.id, p]));

  const historyText = logs.slice(0, 50).map(log => { // Last 50 logs for context
    const pillNames = log.pillIds.map(id => pillLookup.get(id)?.name || "Unknown").join(", ");
    return `[${new Date(log.timestamp).toLocaleString()}] Took: ${pillNames}. Notes: ${log.notes || ''}`;
  }).join("\n");

  const prompt = `
    You are a helpful medical diary assistant.
    User Query: "${query}"

    Here is the recent medication log (User's local time):
    ${historyText}

    Ingredient details for reference:
    ${pills.map(p => `${p.name}: ${p.ingredients.map(i => `${i.name} ${i.dosageMg}mg`).join(', ')}`).join('\n')}

    Answer the user's question based on this data. Be concise. Do not give medical advice.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });
    return response.text || "I couldn't analyze the data at this moment.";
  } catch (e) {
    console.error("AI Analysis Error", e);
    return "Sorry, I encountered an error analyzing your logs.";
  }
};

