import React, { useState } from 'react';
import { Plus, Trash2, Save, X, AlertCircle } from 'lucide-react';
import { Pill, Ingredient } from '../types';
import { generateId } from '../services/storage';

interface PillCabinetProps {
  pills: Pill[];
  onUpdatePills: (pills: Pill[]) => void;
}

const COLORS = ['#14b8a6', '#f59e0b', '#ef4444', '#3b82f6', '#8b5cf6', '#ec4899'];

export const PillCabinet: React.FC<PillCabinetProps> = ({ pills, onUpdatePills }) => {
  const [isAdding, setIsAdding] = useState(false);

  // Form State
  const [name, setName] = useState('');
  const [color, setColor] = useState(COLORS[0]);
  const [ingredients, setIngredients] = useState<Ingredient[]>([{ name: '', dosageMg: 0 }]);

  const handleAddIngredient = () => {
    if (ingredients.length < 3) {
      setIngredients([...ingredients, { name: '', dosageMg: 0 }]);
    }
  };

  const handleIngredientChange = (index: number, field: keyof Ingredient, value: string | number) => {
    const newIngredients = [...ingredients];
    newIngredients[index] = { ...newIngredients[index], [field]: value };
    setIngredients(newIngredients);
  };

  const handleRemoveIngredient = (index: number) => {
    setIngredients(ingredients.filter((_, i) => i !== index));
  };

  const handleSave = () => {
    if (!name.trim()) return;
    const validIngredients = ingredients.filter(i => i.name.trim() && i.dosageMg > 0);

    if (validIngredients.length === 0) {
      alert("Please add at least one valid ingredient.");
      return;
    }

    const newPill: Pill = {
      id: generateId(),
      name,
      color,
      ingredients: validIngredients
    };

    onUpdatePills([...pills, newPill]);
    resetForm();
  };

  const handleDelete = (id: string) => {
    if (window.confirm("Delete this pill definition? Existing logs will keep the ID but details may be lost in display.")) {
      onUpdatePills(pills.filter(p => p.id !== id));
    }
  };

  const resetForm = () => {
    setIsAdding(false);
    setName('');
    setColor(COLORS[0]);
    setIngredients([{ name: '', dosageMg: 0 }]);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Medicine Cabinet</h2>
        {!isAdding && (
          <button
            onClick={() => setIsAdding(true)}
            className="flex items-center space-x-2 bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition shadow-sm"
          >
            <Plus size={20} />
            <span>Add Medication</span>
          </button>
        )}
      </div>

      {isAdding && (
        <div className="bg-white rounded-xl shadow-md p-6 border border-slate-200 animate-fade-in">
          <div className="flex justify-between items-start mb-4">
            <h3 className="text-lg font-semibold text-slate-700">New Medication</h3>
            <button onClick={resetForm} className="text-slate-400 hover:text-slate-600">
              <X size={20} />
            </button>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Medication Name</label>
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full border border-slate-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-teal-500 outline-none"
                placeholder="e.g. Ibuprofen"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-600 mb-2">Label Color</label>
              <div className="flex space-x-2">
                {COLORS.map((c) => (
                  <button
                    key={c}
                    onClick={() => setColor(c)}
                    className={`w-8 h-8 rounded-full border-2 transition ${color === c ? 'border-slate-800 scale-110' : 'border-transparent'}`}
                    style={{ backgroundColor: c }}
                  />
                ))}
              </div>
            </div>

            <div>
              <div className="flex justify-between items-center mb-2">
                <label className="block text-sm font-medium text-slate-600">Ingredients (Max 3)</label>
                {ingredients.length < 3 && (
                  <button onClick={handleAddIngredient} className="text-xs text-teal-600 font-medium hover:underline">
                    + Add Ingredient
                  </button>
                )}
              </div>
              <div className="space-y-3">
                {ingredients.map((ing, idx) => (
                  <div key={idx} className="flex items-center space-x-2">
                    <input
                      type="text"
                      placeholder="Name (e.g. Ibuprofen)"
                      value={ing.name}
                      onChange={(e) => handleIngredientChange(idx, 'name', e.target.value)}
                      className="flex-1 border border-slate-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                    />
                    <input
                      type="number"
                      placeholder="Mg"
                      value={ing.dosageMg || ''}
                      onChange={(e) => handleIngredientChange(idx, 'dosageMg', parseFloat(e.target.value))}
                      className="w-24 border border-slate-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                    />
                    <span className="text-xs text-slate-500">mg</span>
                    {ingredients.length > 1 && (
                      <button onClick={() => handleRemoveIngredient(idx)} className="text-red-400 hover:text-red-600">
                        <Trash2 size={16} />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-4 flex justify-end">
              <button
                onClick={handleSave}
                className="bg-slate-900 text-white px-6 py-2 rounded-lg hover:bg-slate-800 transition flex items-center space-x-2"
              >
                <Save size={18} />
                <span>Save Medication</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {pills.length === 0 && !isAdding && (
          <div className="col-span-full text-center py-12 text-slate-400 flex flex-col items-center">
            <AlertCircle size={48} className="mb-4 opacity-50" />
            <p>Your cabinet is empty. Add your first medication to get started.</p>
          </div>
        )}
        {pills.map((pill) => (
          <div key={pill.id} className="bg-white rounded-xl shadow-sm border border-slate-200 p-5 hover:shadow-md transition">
            <div className="flex justify-between items-start mb-3">
              <div className="flex items-center space-x-3">
                <div className="w-4 h-4 rounded-full" style={{ backgroundColor: pill.color }}></div>
                <h3 className="font-bold text-slate-800 text-lg">{pill.name}</h3>
              </div>
              <button onClick={() => handleDelete(pill.id)} className="text-slate-300 hover:text-red-500 transition">
                <Trash2 size={18} />
              </button>
            </div>
            <div className="space-y-1">
              {pill.ingredients.map((ing, i) => (
                <div key={i} className="text-sm text-slate-600 flex justify-between border-b border-slate-50 last:border-0 py-1">
                  <span>{ing.name}</span>
                  <span className="font-mono text-slate-500">{ing.dosageMg}mg</span>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Calendar, Clock, Check } from 'lucide-react';
import { Pill, LogEntry } from '../types';
import { generateId } from '../services/storage';

interface LogModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (entry: LogEntry) => void;
  availablePills: Pill[];
  initialEntry?: LogEntry | null;
}

export const LogModal: React.FC<LogModalProps> = ({ isOpen, onClose, onSave, availablePills, initialEntry }) => {
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [selectedPills, setSelectedPills] = useState<string[]>([]);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    if (isOpen) {
      if (initialEntry) {
        const d = new Date(initialEntry.timestamp);
        setDate(d.toISOString().split('T')[0]);
        setTime(d.toTimeString().split(' ')[0].substring(0, 5));
        setSelectedPills(initialEntry.pillIds);
        setNotes(initialEntry.notes || '');
      } else {
        const now = new Date();
        setDate(now.toISOString().split('T')[0]);
        setTime(now.toTimeString().split(' ')[0].substring(0, 5));
        setSelectedPills([]);
        setNotes('');
      }
    }
  }, [isOpen, initialEntry]);

  if (!isOpen) return null;

  const handleTogglePill = (id: string) => {
    if (selectedPills.includes(id)) {
      setSelectedPills(selectedPills.filter(p => p !== id));
    } else {
      if (selectedPills.length < 3) {
        setSelectedPills([...selectedPills, id]);
      }
    }
  };

  const handleSubmit = () => {
    if (selectedPills.length === 0) {
      alert("Please select at least one pill.");
      return;
    }

    const timestamp = new Date(`${date}T${time}`).getTime();

    const entry: LogEntry = {
      id: initialEntry?.id || generateId(),
      timestamp,
      pillIds: selectedPills,
      notes
    };

    onSave(entry);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden animate-fade-in-up">
        <div className="bg-slate-900 px-6 py-4 flex justify-between items-center text-white">
          <h3 className="font-bold text-lg">{initialEntry ? 'Edit Entry' : 'Log Medication'}</h3>
          <button onClick={onClose} className="hover:bg-slate-700 p-1 rounded transition">
            <X size={20} />
          </button>
        </div>

        <div className="p-6 space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Date</label>
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input
                  type="date"
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  className="w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                />
              </div>
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Time</label>
              <div className="relative">
                <Clock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input
                  type="time"
                  value={time}
                  onChange={(e) => setTime(e.target.value)}
                  className="w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                />
              </div>
            </div>
          </div>

          <div>
            <div className="flex justify-between items-end mb-2">
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider">Select Pills (Max 3)</label>
              <span className="text-xs text-teal-600">{selectedPills.length}/3 selected</span>
            </div>
            <div className="grid grid-cols-2 gap-2 max-h-48 overflow-y-auto p-1">
              {availablePills.map(pill => {
                const isSelected = selectedPills.includes(pill.id);
                return (
                  <button
                    key={pill.id}
                    onClick={() => handleTogglePill(pill.id)}
                    disabled={!isSelected && selectedPills.length >= 3}
                    className={`flex items-center p-3 rounded-lg border text-left transition ${
                      isSelected 
                        ? 'border-teal-500 bg-teal-50 text-teal-900 ring-1 ring-teal-500' 
                        : 'border-slate-200 hover:border-slate-300 text-slate-700'
                    } ${!isSelected && selectedPills.length >= 3 ? 'opacity-50 cursor-not-allowed' : ''}`}
                  >
                    <div className="w-3 h-3 rounded-full mr-3 shrink-0" style={{ backgroundColor: pill.color }}></div>
                    <span className="text-sm font-medium truncate">{pill.name}</span>
                    {isSelected && <Check size={16} className="ml-auto text-teal-600" />}
                  </button>
                );
              })}
              {availablePills.length === 0 && (
                <div className="col-span-2 text-center text-sm text-slate-500 py-4 border border-dashed border-slate-300 rounded-lg">
                  No pills configured. Go to Cabinet first.
                </div>
              )}
            </div>
          </div>

          <div>
            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Notes (Optional)</label>
            <textarea
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm h-20 focus:ring-2 focus:ring-teal-500 outline-none resize-none"
              placeholder="How are you feeling?"
            />
          </div>
        </div>

        <div className="bg-slate-50 px-6 py-4 flex justify-end">
          <button onClick={onClose} className="mr-3 px-4 py-2 text-slate-600 hover:text-slate-800 text-sm font-medium">Cancel</button>
          <button 
            onClick={handleSubmit} 
            disabled={availablePills.length === 0}
            className="bg-slate-900 text-white px-6 py-2 rounded-lg text-sm font-medium hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
          >
            Save Entry
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User as UserIcon, Loader2, Sparkles } from 'lucide-react';
import { Pill, LogEntry } from '../types';
import { analyzeHistory, parseNaturalLanguageLog } from '../services/geminiService';

interface AIAssistantProps {
  logs: LogEntry[];
  pills: Pill[];
  onAddLog: (log: LogEntry) => void;
}

interface Message {
  role: 'user' | 'ai';
  content: string;
}

export const AIAssistant: React.FC<AIAssistantProps> = ({ logs, pills, onAddLog }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { role: 'ai', content: "Hello! I can help you analyze your history or log medications. Try saying 'I took 2 Ibuprofen just now' or 'How much Caffeine did I have yesterday?'" }
  ]);
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userText = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userText }]);
    setLoading(true);

    try {
      // Heuristic: Check if user is trying to LOG something or ASK something
      const isLogIntent = /took|swallowed|ate|had|logging/i.test(userText);

      let aiResponse = "";

      if (isLogIntent) {
        const parsed = await parseNaturalLanguageLog(userText, pills);
        if (parsed && parsed.pillIds.length > 0) {
          // Construct the log entry
          const newEntry: LogEntry = {
            id: Math.random().toString(36).substr(2, 9),
            timestamp: Date.now(),
            pillIds: parsed.pillIds,
            notes: parsed.notes
          };
          onAddLog(newEntry);

          const pillNames = parsed.pillIds.map(id => pills.find(p => p.id === id)?.name).join(", ");
          aiResponse = `I've logged that for you: ${pillNames}.`;
        } else {
          aiResponse = "I couldn't identify the specific pills from your cabinet. Please make sure the name matches what you've saved in the Cabinet tab.";
        }
      } else {
        // Analysis Intent
        aiResponse = await analyzeHistory(userText, logs, pills);
      }

      setMessages(prev => [...prev, { role: 'ai', content: aiResponse }]);

    } catch (error) {
      setMessages(prev => [...prev, { role: 'ai', content: "Sorry, I had trouble connecting to my brain. Please try again." }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-xl shadow-md border border-slate-200 overflow-hidden">
      <div className="bg-gradient-to-r from-violet-600 to-indigo-600 p-4 text-white flex items-center space-x-2">
        <Sparkles size={20} className="text-yellow-300" />
        <h2 className="font-bold">Health Assistant</h2>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex max-w-[80%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'} items-start gap-2`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${m.role === 'user' ? 'bg-slate-700' : 'bg-indigo-100'}`}>
                {m.role === 'user' ? <UserIcon size={14} className="text-white" /> : <Bot size={16} className="text-indigo-600" />}
              </div>
              <div className={`p-3 rounded-2xl text-sm leading-relaxed shadow-sm ${
                m.role === 'user' 
                  ? 'bg-slate-800 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 border border-slate-200 rounded-tl-none'
              }`}>
                {m.content}
              </div>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
             <div className="flex flex-row items-center gap-2">
                <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center shrink-0">
                  <Bot size={16} className="text-indigo-600" />
                </div>
                <div className="bg-white p-3 rounded-2xl rounded-tl-none border border-slate-200 shadow-sm flex items-center space-x-2">
                   <Loader2 size={16} className="animate-spin text-indigo-600" />
                   <span className="text-xs text-slate-500">Thinking...</span>
                </div>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white border-t border-slate-200">
        <div className="flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Log a pill or ask about your history..."
            className="flex-1 border border-slate-300 rounded-full px-4 py-2.5 focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
          />
          <button
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="bg-indigo-600 text-white p-2.5 rounded-full hover:bg-indigo-700 disabled:opacity-50 transition"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { Edit2, Pill as PillIcon, Calendar as CalendarIcon, Activity } from 'lucide-react';
import { LogEntry, Pill, DailyAggregation } from '../types';

interface DashboardProps {
  logs: LogEntry[];
  pills: Pill[];
  onEditLog: (entry: LogEntry) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ logs, pills, onEditLog }) => {
  const aggregatedData = useMemo(() => {
    const grouped: Record<string, DailyAggregation> = {};

    // Sort logs descending
    const sortedLogs = [...logs].sort((a, b) => b.timestamp - a.timestamp);

    sortedLogs.forEach(log => {
      const dateKey = new Date(log.timestamp).toLocaleDateString('en-CA'); // YYYY-MM-DD

      if (!grouped[dateKey]) {
        grouped[dateKey] = {
          date: dateKey,
          logs: [],
          totalIngredients: {}
        };
      }

      grouped[dateKey].logs.push(log);

      // Aggregate Ingredients
      log.pillIds.forEach(pId => {
        const pill = pills.find(p => p.id === pId);
        if (pill) {
          pill.ingredients.forEach(ing => {
            const current = grouped[dateKey].totalIngredients[ing.name] || 0;
            grouped[dateKey].totalIngredients[ing.name] = current + ing.dosageMg;
          });
        }
      });
    });

    return Object.values(grouped).sort((a, b) => b.date.localeCompare(a.date));
  }, [logs, pills]);

  const getPillDetails = (id: string) => pills.find(p => p.id === id);

  if (logs.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-slate-400">
        <Activity size={64} className="mb-4 text-slate-300" />
        <p className="text-lg">No logs recorded yet.</p>
        <p className="text-sm">Click "Log Now" to start tracking.</p>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in">
      {aggregatedData.map((day) => (
        <div key={day.date} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          {/* Day Header */}
          <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
            <div className="flex items-center space-x-3">
              <CalendarIcon className="text-teal-600" size={20} />
              <h3 className="font-bold text-lg text-slate-800">
                {new Date(day.date).toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
              </h3>
            </div>
            <div className="text-xs text-slate-500 font-medium px-2 py-1 bg-slate-200 rounded">
              {day.logs.length} Entries
            </div>
          </div>

          <div className="p-6 grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Left: Detailed Timeline */}
            <div className="lg:col-span-2 space-y-4">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Timeline</h4>
              {day.logs.map(log => (
                <div key={log.id} className="relative pl-6 border-l-2 border-slate-200 hover:border-teal-400 transition-colors group">
                  <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-slate-200 group-hover:bg-teal-500 transition-colors"></div>
                  <div className="flex justify-between items-start mb-1">
                    <span className="text-sm font-mono text-slate-500">
                      {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </span>
                    <button 
                      onClick={() => onEditLog(log)}
                      className="text-slate-300 hover:text-teal-600 transition opacity-0 group-hover:opacity-100"
                    >
                      <Edit2 size={14} />
                    </button>
                  </div>

                  <div className="flex flex-wrap gap-2 mb-2">
                    {log.pillIds.map((pid, idx) => {
                      const pill = getPillDetails(pid);
                      return pill ? (
                        <div key={`${log.id}-${idx}`} className="flex items-center space-x-1 bg-slate-100 px-2 py-1 rounded-full text-xs font-medium text-slate-700 border border-slate-200">
                          <div className="w-2 h-2 rounded-full" style={{ backgroundColor: pill.color }}></div>
                          <span>{pill.name}</span>
                        </div>
                      ) : (
                        <span key={idx} className="text-xs text-red-400">Unknown Pill</span>
                      );
                    })}
                  </div>

                  {log.notes && (
                    <p className="text-xs text-slate-500 italic bg-slate-50 p-2 rounded border border-slate-100 inline-block">
                      "{log.notes}"
                    </p>
                  )}
                </div>
              ))}
            </div>

            {/* Right: Ingredient Totals */}
            <div className="bg-slate-50 rounded-xl p-5 h-fit">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center">
                <Activity size={14} className="mr-2" />
                Daily Intake Totals
              </h4>
              <div className="space-y-3">
                {Object.entries(day.totalIngredients).map(([name, total]) => (
                  <div key={name} className="flex justify-between items-center border-b border-slate-200 last:border-0 pb-2 last:pb-0">
                    <span className="text-sm font-medium text-slate-700">{name}</span>
                    <span className="text-sm font-bold text-teal-700">{total} mg</span>
                  </div>
                ))}
                {Object.keys(day.totalIngredients).length === 0 && (
                  <div className="text-sm text-slate-400 italic text-center">No ingredients tracked.</div>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
