        onClose={() => setIsLogModalOpen(false)} 
        onSave={handleSaveLog}
        availablePills={user.pills}
        initialEntry={editingLog}
      />
    </div>
  );
}

export default App;

export interface Ingredient {
  name: string;
  dosageMg: number;
}

export interface Pill {
  id: string;
  name: string;
  ingredients: Ingredient[]; // Max 3
  color: string;
}

export interface PillTaken {
  pillId: string;
  quantity: number;
}

export interface LogEntry {
  id: string;
  timestamp: number;
  pillsTaken: PillTaken[]; 
  pillIds?: string[]; // Legacy field for backward compatibility
  notes?: string;
}

export interface UserData {
  email: string;
  pills: Pill[];
  logs: LogEntry[];
}

export interface DailyAggregation {
  date: string; // YYYY-MM-DD
  logs: LogEntry[];
  totalIngredients: Record<string, number>; // Ingredient Name -> Total Mg
}

export enum AppTab {
  DASHBOARD = 'dashboard',
  CABINET = 'cabinet',
  ASSISTANT = 'assistant',
}

import { UserData, Pill, LogEntry } from '../types';

const STORAGE_KEY_PREFIX = 'medtrack_user_';

export const loadUserData = (email: string): UserData => {
  const key = `${STORAGE_KEY_PREFIX}${email.toLowerCase().trim()}`;
  const stored = localStorage.getItem(key);
  if (stored) {
    const data = JSON.parse(stored);

    // Data Migration: Convert legacy pillIds to pillsTaken
    if (data.logs) {
      data.logs = data.logs.map((log: any) => {
        if (!log.pillsTaken && log.pillIds) {
          return {
            ...log,
            pillsTaken: log.pillIds.map((id: string) => ({ pillId: id, quantity: 1 })),
          };
        }
        return log;
      });
    }

    return data;
  }
  return {
    email,
    pills: [],
    logs: [],
  };
};

export const saveUserData = (data: UserData) => {
  const key = `${STORAGE_KEY_PREFIX}${data.email.toLowerCase().trim()}`;
  localStorage.setItem(key, JSON.stringify(data));
};

export const generateId = () => Math.random().toString(36).substring(2, 9);

import React, { useState, useEffect } from 'react';
import { X, Calendar, Clock, Minus, Plus } from 'lucide-react';
import { Pill, LogEntry, PillTaken } from '../types';
import { generateId } from '../services/storage';

interface LogModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (entry: LogEntry) => void;
  availablePills: Pill[];
  initialEntry?: LogEntry | null;
}

export const LogModal: React.FC<LogModalProps> = ({ isOpen, onClose, onSave, availablePills, initialEntry }) => {
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [selectedPills, setSelectedPills] = useState<PillTaken[]>([]);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    if (isOpen) {
      if (initialEntry) {
        const d = new Date(initialEntry.timestamp);
        setDate(d.toISOString().split('T')[0]);
        setTime(d.toTimeString().split(' ')[0].substring(0, 5));

        // Handle migration for editing old entries
        if (initialEntry.pillsTaken) {
          setSelectedPills(initialEntry.pillsTaken);
        } else if (initialEntry.pillIds) {
          setSelectedPills(initialEntry.pillIds.map(id => ({ pillId: id, quantity: 1 })));
        }

        setNotes(initialEntry.notes || '');
      } else {
        const now = new Date();
        setDate(now.toISOString().split('T')[0]);
        setTime(now.toTimeString().split(' ')[0].substring(0, 5));
        setSelectedPills([]);
        setNotes('');
      }
    }
  }, [isOpen, initialEntry]);

  if (!isOpen) return null;

  const handleUpdateQuantity = (id: string, delta: number) => {
    const existingIndex = selectedPills.findIndex(p => p.pillId === id);

    if (existingIndex >= 0) {
      const newPills = [...selectedPills];
      const newQty = Math.max(0, newPills[existingIndex].quantity + delta);

      if (newQty === 0) {
        // Remove pill if qty goes to 0
        newPills.splice(existingIndex, 1);
      } else {
        newPills[existingIndex].quantity = newQty;
      }
      setSelectedPills(newPills);
    } else if (delta > 0) {
      // Add new pill
      if (selectedPills.length < 5) {
        setSelectedPills([...selectedPills, { pillId: id, quantity: delta }]);
      }
    }
  };

  const handleSubmit = () => {
    if (selectedPills.length === 0) {
      alert("Please select at least one pill.");
      return;
    }

    const timestamp = new Date(`${date}T${time}`).getTime();

    const entry: LogEntry = {
      id: initialEntry?.id || generateId(),
      timestamp,
      pillsTaken: selectedPills,
      pillIds: selectedPills.map(p => p.pillId), // Maintain legacy sync just in case
      notes
    };

    onSave(entry);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden animate-fade-in-up flex flex-col max-h-[90vh]">
        <div className="bg-slate-900 px-6 py-4 flex justify-between items-center text-white shrink-0">
          <h3 className="font-bold text-lg">{initialEntry ? 'Edit Entry' : 'Log Medication'}</h3>
          <button onClick={onClose} className="hover:bg-slate-700 p-1 rounded transition">
            <X size={20} />
          </button>
        </div>

        <div className="p-6 space-y-6 overflow-y-auto">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Date</label>
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input
                  type="date"
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  className="w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                />
              </div>
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Time</label>
              <div className="relative">
                <Clock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input
                  type="time"
                  value={time}
                  onChange={(e) => setTime(e.target.value)}
                  className="w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                />
              </div>
            </div>
          </div>

          <div>
            <div className="flex justify-between items-end mb-2">
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider">Select Pills (Max 5)</label>
              <span className="text-xs text-teal-600">{selectedPills.length}/5 distinct items</span>
            </div>
            <div className="grid grid-cols-1 gap-2 p-1">
              {availablePills.map(pill => {
                const selection = selectedPills.find(p => p.pillId === pill.id);
                const quantity = selection ? selection.quantity : 0;

                return (
                  <div
                    key={pill.id}
                    className={`flex items-center justify-between p-3 rounded-lg border transition ${
                      quantity > 0
                        ? 'border-teal-500 bg-teal-50 ring-1 ring-teal-500' 
                        : 'border-slate-200 bg-white'
                    }`}
                  >
                    <div className="flex items-center flex-1 min-w-0">
                        <div className="w-3 h-3 rounded-full mr-3 shrink-0" style={{ backgroundColor: pill.color }}></div>
                        <span className={`text-sm font-medium truncate ${quantity > 0 ? 'text-teal-900' : 'text-slate-700'}`}>
                            {pill.name}
                        </span>
                    </div>

                    <div className="flex items-center space-x-3 ml-4">
                        {quantity > 0 ? (
                             <div className="flex items-center bg-white rounded-md border border-teal-200 shadow-sm">
                                <button 
                                    onClick={() => handleUpdateQuantity(pill.id, -0.5)}
                                    className="p-1.5 text-teal-700 hover:bg-teal-100 rounded-l-md transition"
                                >
                                    <Minus size={14} />
                                </button>
                                <span className="w-8 text-center text-sm font-bold text-teal-800">{quantity}</span>
                                <button 
                                    onClick={() => handleUpdateQuantity(pill.id, 0.5)}
                                    className="p-1.5 text-teal-700 hover:bg-teal-100 rounded-r-md transition"
                                >
                                    <Plus size={14} />
                                </button>
                             </div>
                        ) : (
                             <button
                                onClick={() => handleUpdateQuantity(pill.id, 1)}
                                disabled={selectedPills.length >= 5}
                                className="px-3 py-1.5 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded text-xs font-semibold uppercase tracking-wide transition disabled:opacity-50"
                             >
                                Add
                             </button>
                        )}
                    </div>
                  </div>
                );
              })}
              {availablePills.length === 0 && (
                <div className="text-center text-sm text-slate-500 py-4 border border-dashed border-slate-300 rounded-lg">
                  No pills configured. Go to Cabinet first.
                </div>
              )}
            </div>
          </div>

          <div>
            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Notes (Optional)</label>
            <textarea
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm h-20 focus:ring-2 focus:ring-teal-500 outline-none resize-none"
              placeholder="How are you feeling?"
            />
          </div>
        </div>

        <div className="bg-slate-50 px-6 py-4 flex justify-end shrink-0">
          <button onClick={onClose} className="mr-3 px-4 py-2 text-slate-600 hover:text-slate-800 text-sm font-medium">Cancel</button>
          <button 
            onClick={handleSubmit} 
            disabled={availablePills.length === 0}
            className="bg-slate-900 text-white px-6 py-2 rounded-lg text-sm font-medium hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
          >
            Save Entry
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { Edit2, Pill as PillIcon, Calendar as CalendarIcon, Activity } from 'lucide-react';
import { LogEntry, Pill, DailyAggregation } from '../types';

interface DashboardProps {
  logs: LogEntry[];
  pills: Pill[];
  onEditLog: (entry: LogEntry) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ logs, pills, onEditLog }) => {
  const aggregatedData = useMemo(() => {
    const grouped: Record<string, DailyAggregation> = {};

    // Sort logs descending
    const sortedLogs = [...logs].sort((a, b) => b.timestamp - a.timestamp);

    sortedLogs.forEach(log => {
      const dateKey = new Date(log.timestamp).toLocaleDateString('en-CA'); // YYYY-MM-DD

      if (!grouped[dateKey]) {
        grouped[dateKey] = {
          date: dateKey,
          logs: [],
          totalIngredients: {}
        };
      }

      grouped[dateKey].logs.push(log);

      // Aggregate Ingredients
      if (log.pillsTaken) {
        log.pillsTaken.forEach(item => {
          const pill = pills.find(p => p.id === item.pillId);
          if (pill) {
            pill.ingredients.forEach(ing => {
              const current = grouped[dateKey].totalIngredients[ing.name] || 0;
              // Multiply dosage by quantity taken
              grouped[dateKey].totalIngredients[ing.name] = current + (ing.dosageMg * item.quantity);
            });
          }
        });
      }
    });

    return Object.values(grouped).sort((a, b) => b.date.localeCompare(a.date));
  }, [logs, pills]);

  const getPillDetails = (id: string) => pills.find(p => p.id === id);

  if (logs.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-slate-400">
        <Activity size={64} className="mb-4 text-slate-300" />
        <p className="text-lg">No logs recorded yet.</p>
        <p className="text-sm">Click "Log Now" to start tracking.</p>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in">
      {aggregatedData.map((day) => (
        <div key={day.date} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          {/* Day Header */}
          <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
            <div className="flex items-center space-x-3">
              <CalendarIcon className="text-teal-600" size={20} />
              <h3 className="font-bold text-lg text-slate-800">
                {new Date(day.date).toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
              </h3>
            </div>
            <div className="text-xs text-slate-500 font-medium px-2 py-1 bg-slate-200 rounded">
              {day.logs.length} Entries
            </div>
          </div>

          <div className="p-6 grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Left: Detailed Timeline */}
            <div className="lg:col-span-2 space-y-4">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Timeline</h4>
              {day.logs.map(log => (
                <div key={log.id} className="relative pl-6 border-l-2 border-slate-200 hover:border-teal-400 transition-colors group">
                  <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-slate-200 group-hover:bg-teal-500 transition-colors"></div>
                  <div className="flex justify-between items-start mb-1">
                    <span className="text-sm font-mono text-slate-500">
                      {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </span>
                    <button 
                      onClick={() => onEditLog(log)}
                      className="text-slate-300 hover:text-teal-600 transition opacity-0 group-hover:opacity-100"
                    >
                      <Edit2 size={14} />
                    </button>
                  </div>

                  <div className="flex flex-wrap gap-2 mb-2">
                    {log.pillsTaken?.map((item, idx) => {
                      const pill = getPillDetails(item.pillId);
                      return pill ? (
                        <div key={`${log.id}-${idx}`} className="flex items-center space-x-1 bg-slate-100 px-2 py-1 rounded-full text-xs font-medium text-slate-700 border border-slate-200">
                          <div className="w-2 h-2 rounded-full" style={{ backgroundColor: pill.color }}></div>
                          <span className="font-bold">{item.quantity}x</span>
                          <span>{pill.name}</span>
                        </div>
                      ) : (
                        <span key={idx} className="text-xs text-red-400">Unknown Pill</span>
                      );
                    })}
                  </div>

                  {log.notes && (
                    <p className="text-xs text-slate-500 italic bg-slate-50 p-2 rounded border border-slate-100 inline-block">
                      "{log.notes}"
                    </p>
                  )}
                </div>
              ))}
            </div>

            {/* Right: Ingredient Totals */}
            <div className="bg-slate-50 rounded-xl p-5 h-fit">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center">
                <Activity size={14} className="mr-2" />
                Daily Intake Totals
              </h4>
              <div className="space-y-3">
                {Object.entries(day.totalIngredients).map(([name, total]) => (
                  <div key={name} className="flex justify-between items-center border-b border-slate-200 last:border-0 pb-2 last:pb-0">
                    <span className="text-sm font-medium text-slate-700">{name}</span>
                    <span className="text-sm font-bold text-teal-700">{total} mg</span>
                  </div>
                ))}
                {Object.keys(day.totalIngredients).length === 0 && (
                  <div className="text-sm text-slate-400 italic text-center">No ingredients tracked.</div>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Pill, LogEntry, PillTaken } from '../types';

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Parses a natural language string to suggest a log entry.
 */
export const parseNaturalLanguageLog = async (
  input: string,
  availablePills: Pill[]
): Promise<{ pillsTaken: PillTaken[], notes: string, confidence: string } | null> => {
  const ai = getAI();

  const pillMap = availablePills.map(p => ({ id: p.id, name: p.name })).map(p => `${p.name} (ID: ${p.id})`).join(', ');

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      pillsTaken: {
        type: Type.ARRAY,
        items: { 
            type: Type.OBJECT,
            properties: {
                pillId: { type: Type.STRING },
                quantity: { type: Type.NUMBER, description: "Amount taken, e.g. 1, 2, 0.5" }
            },
            required: ["pillId", "quantity"]
        },
        description: "List of Pills extracted from text."
      },
      notes: {
        type: Type.STRING,
        description: "Any extra context mentioned (e.g., 'after dinner', 'headache')."
      },
      confidence: {
        type: Type.STRING,
        enum: ["HIGH", "LOW"],
        description: "Confidence level of the match."
      }
    },
    required: ["pillsTaken", "confidence"]
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `User Input: "${input}". 
      Available Pills: [${pillMap}].
      Task: Extract the pills taken. If a pill name roughly matches an available pill, include its ID and the quantity mentioned (default to 1 if not specified). Max 5 pills.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      }
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    return null;
  } catch (e) {
    console.error("AI Parse Error", e);
    return null;
  }
};

/**
 * Answers questions about the user's log history.
 */
export const analyzeHistory = async (
  query: string,
  logs: LogEntry[],
  pills: Pill[]
): Promise<string> => {
  const ai = getAI();

  // Create a minified text representation of the data to fit context
  const pillLookup = new Map(pills.map(p => [p.id, p]));

  const historyText = logs.slice(0, 50).map(log => { // Last 50 logs for context
    const items = log.pillsTaken?.map(item => {
        const p = pillLookup.get(item.pillId);
        return p ? `${item.quantity}x ${p.name}` : `${item.quantity}x Unknown`;
    }).join(", ");

    // Fallback for migration if pillsTaken is missing but pillIds exists in older runtime memory
    const legacyItems = !log.pillsTaken && log.pillIds ? log.pillIds.map(id => pillLookup.get(id)?.name).join(", ") : "";

    return `[${new Date(log.timestamp).toLocaleString()}] Took: ${items || legacyItems}. Notes: ${log.notes || ''}`;
  }).join("\n");

  const prompt = `
    You are a helpful medical diary assistant.
    User Query: "${query}"

    Here is the recent medication log (User's local time):
    ${historyText}

    Ingredient details for reference:
    ${pills.map(p => `${p.name}: ${p.ingredients.map(i => `${i.name} ${i.dosageMg}mg`).join(', ')}`).join('\n')}

    Answer the user's question based on this data. Be concise. Do not give medical advice.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });
    return response.text || "I couldn't analyze the data at this moment.";
  } catch (e) {
    console.error("AI Analysis Error", e);
    return "Sorry, I encountered an error analyzing your logs.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User as UserIcon, Loader2, Sparkles } from 'lucide-react';
import { Pill, LogEntry } from '../types';
import { analyzeHistory, parseNaturalLanguageLog } from '../services/geminiService';

interface AIAssistantProps {
  logs: LogEntry[];
  pills: Pill[];
  onAddLog: (log: LogEntry) => void;
}

interface Message {
  role: 'user' | 'ai';
  content: string;
}

export const AIAssistant: React.FC<AIAssistantProps> = ({ logs, pills, onAddLog }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { role: 'ai', content: "Hello! I can help you analyze your history or log medications. Try saying 'I took 2 Ibuprofen just now' or 'How much Caffeine did I have yesterday?'" }
  ]);
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userText = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userText }]);
    setLoading(true);

    try {
      // Heuristic: Check if user is trying to LOG something or ASK something
      const isLogIntent = /took|swallowed|ate|had|logging/i.test(userText);

      let aiResponse = "";

      if (isLogIntent) {
        const parsed = await parseNaturalLanguageLog(userText, pills);
        if (parsed && parsed.pillsTaken.length > 0) {
          // Construct the log entry
          const newEntry: LogEntry = {
            id: Math.random().toString(36).substr(2, 9),
            timestamp: Date.now(),
            pillsTaken: parsed.pillsTaken,
            pillIds: parsed.pillsTaken.map(p => p.pillId), // Legacy support
            notes: parsed.notes
          };
          onAddLog(newEntry);

          const pillSummary = parsed.pillsTaken.map(item => {
             const name = pills.find(p => p.id === item.pillId)?.name;
             return `${item.quantity}x ${name}`;
          }).join(", ");

          aiResponse = `I've logged that for you: ${pillSummary}.`;
        } else {
          aiResponse = "I couldn't identify the specific pills from your cabinet. Please make sure the name matches what you've saved in the Cabinet tab.";
        }
      } else {
        // Analysis Intent
        aiResponse = await analyzeHistory(userText, logs, pills);
      }

      setMessages(prev => [...prev, { role: 'ai', content: aiResponse }]);

    } catch (error) {
      setMessages(prev => [...prev, { role: 'ai', content: "Sorry, I had trouble connecting to my brain. Please try again." }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-xl shadow-md border border-slate-200 overflow-hidden">
      <div className="bg-gradient-to-r from-violet-600 to-indigo-600 p-4 text-white flex items-center space-x-2">
        <Sparkles size={20} className="text-yellow-300" />
        <h2 className="font-bold">Health Assistant</h2>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex max-w-[80%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'} items-start gap-2`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${m.role === 'user' ? 'bg-slate-700' : 'bg-indigo-100'}`}>
                {m.role === 'user' ? <UserIcon size={14} className="text-white" /> : <Bot size={16} className="text-indigo-600" />}
              </div>
              <div className={`p-3 rounded-2xl text-sm leading-relaxed shadow-sm ${
                m.role === 'user' 
                  ? 'bg-slate-800 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 border border-slate-200 rounded-tl-none'
              }`}>
                {m.content}
              </div>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
             <div className="flex flex-row items-center gap-2">
                <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center shrink-0">
                  <Bot size={16} className="text-indigo-600" />
                </div>
                <div className="bg-white p-3 rounded-2xl rounded-tl-none border border-slate-200 shadow-sm flex items-center space-x-2">
                   <Loader2 size={16} className="animate-spin text-indigo-600" />
                   <span className="text-xs text-slate-500">Thinking...</span>
                </div>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white border-t border-slate-200">
        <div className="flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Log a pill or ask about your history..."
            className="flex-1 border border-slate-300 rounded-full px-4 py-2.5 focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
          />
          <button
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="bg-indigo-600 text-white p-2.5 rounded-full hover:bg-indigo-700 disabled:opacity-50 transition"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

