              >
                Save Entry
              </button>
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Plus, Trash2, Save, X, AlertCircle, Edit2 } from 'lucide-react';
import { Pill, Ingredient } from '../types';
import { generateId } from '../services/storage';

interface PillCabinetProps {
  pills: Pill[];
  onUpdatePills: (pills: Pill[]) => void;
}

const COLORS = ['#14b8a6', '#f59e0b', '#ef4444', '#3b82f6', '#8b5cf6', '#ec4899'];

export const PillCabinet: React.FC<PillCabinetProps> = ({ pills, onUpdatePills }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Form State
  const [name, setName] = useState('');
  const [color, setColor] = useState(COLORS[0]);
  const [ingredients, setIngredients] = useState<Ingredient[]>([{ name: '', dosageMg: 0 }]);

  const handleAddIngredient = () => {
    if (ingredients.length < 3) {
      setIngredients([...ingredients, { name: '', dosageMg: 0 }]);
    }
  };

  const handleIngredientChange = (index: number, field: keyof Ingredient, value: string | number) => {
    const newIngredients = [...ingredients];
    newIngredients[index] = { ...newIngredients[index], [field]: value };
    setIngredients(newIngredients);
  };

  const handleRemoveIngredient = (index: number) => {
    setIngredients(ingredients.filter((_, i) => i !== index));
  };

  const handleEditStart = (pill: Pill) => {
    setEditingId(pill.id);
    setName(pill.name);
    setColor(pill.color);
    // Deep copy ingredients to avoid mutating the pill directly during edit
    setIngredients(pill.ingredients.map(i => ({...i})));
    setIsAdding(true);
  };

  const handleSave = () => {
    if (!name.trim()) return;
    const validIngredients = ingredients.filter(i => i.name.trim() && i.dosageMg > 0);

    if (validIngredients.length === 0) {
      alert("Please add at least one valid ingredient.");
      return;
    }

    if (editingId) {
        // Update existing pill
        const updatedPills = pills.map(p => {
            if (p.id === editingId) {
                return {
                    ...p,
                    name,
                    color,
                    ingredients: validIngredients
                };
            }
            return p;
        });
        onUpdatePills(updatedPills);
    } else {
        // Add new pill
        const newPill: Pill = {
            id: generateId(),
            name,
            color,
            ingredients: validIngredients
        };
        onUpdatePills([...pills, newPill]);
    }
    resetForm();
  };

  const handleDelete = (id: string) => {
    if (window.confirm("Delete this pill definition? Existing logs will keep the ID but details may be lost in display.")) {
      onUpdatePills(pills.filter(p => p.id !== id));
    }
  };

  const resetForm = () => {
    setIsAdding(false);
    setEditingId(null);
    setName('');
    setColor(COLORS[0]);
    setIngredients([{ name: '', dosageMg: 0 }]);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Medicine Cabinet</h2>
        {!isAdding && (
          <button
            onClick={() => { resetForm(); setIsAdding(true); }}
            className="flex items-center space-x-2 bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition shadow-sm"
          >
            <Plus size={20} />
            <span>Add Medication</span>
          </button>
        )}
      </div>

      {isAdding && (
        <div className="bg-white rounded-xl shadow-md p-6 border border-slate-200 animate-fade-in">
          <div className="flex justify-between items-start mb-4">
            <h3 className="text-lg font-semibold text-slate-700">{editingId ? 'Edit Medication' : 'New Medication'}</h3>
            <button onClick={resetForm} className="text-slate-400 hover:text-slate-600">
              <X size={20} />
            </button>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Medication Name</label>
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full border border-slate-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-teal-500 outline-none"
                placeholder="e.g. Ibuprofen"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-600 mb-2">Label Color</label>
              <div className="flex space-x-2">
                {COLORS.map((c) => (
                  <button
                    key={c}
                    onClick={() => setColor(c)}
                    className={`w-8 h-8 rounded-full border-2 transition ${color === c ? 'border-slate-800 scale-110' : 'border-transparent'}`}
                    style={{ backgroundColor: c }}
                  />
                ))}
              </div>
            </div>

            <div>
              <div className="flex justify-between items-center mb-2">
                <label className="block text-sm font-medium text-slate-600">Ingredients (Max 3)</label>
                {ingredients.length < 3 && (
                  <button onClick={handleAddIngredient} className="text-xs text-teal-600 font-medium hover:underline">
                    + Add Ingredient
                  </button>
                )}
              </div>
              <div className="space-y-3">
                {ingredients.map((ing, idx) => (
                  <div key={idx} className="flex items-center space-x-2">
                    <input
                      type="text"
                      placeholder="Name (e.g. Ibuprofen)"
                      value={ing.name}
                      onChange={(e) => handleIngredientChange(idx, 'name', e.target.value)}
                      className="flex-1 border border-slate-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                    />
                    <input
                      type="number"
                      placeholder="Mg"
                      value={ing.dosageMg || ''}
                      onChange={(e) => handleIngredientChange(idx, 'dosageMg', parseFloat(e.target.value))}
                      className="w-24 border border-slate-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                    />
                    <span className="text-xs text-slate-500">mg</span>
                    {ingredients.length > 1 && (
                      <button onClick={() => handleRemoveIngredient(idx)} className="text-red-400 hover:text-red-600">
                        <Trash2 size={16} />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-4 flex justify-end">
              <button
                onClick={handleSave}
                className="bg-slate-900 text-white px-6 py-2 rounded-lg hover:bg-slate-800 transition flex items-center space-x-2"
              >
                <Save size={18} />
                <span>{editingId ? 'Update Medication' : 'Save Medication'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {pills.length === 0 && !isAdding && (
          <div className="col-span-full text-center py-12 text-slate-400 flex flex-col items-center">
            <AlertCircle size={48} className="mb-4 opacity-50" />
            <p>Your cabinet is empty. Add your first medication to get started.</p>
          </div>
        )}
        {pills.map((pill) => (
          <div key={pill.id} className="bg-white rounded-xl shadow-sm border border-slate-200 p-5 hover:shadow-md transition">
            <div className="flex justify-between items-start mb-3">
              <div className="flex items-center space-x-3">
                <div className="w-4 h-4 rounded-full" style={{ backgroundColor: pill.color }}></div>
                <h3 className="font-bold text-slate-800 text-lg">{pill.name}</h3>
              </div>
              <div className="flex space-x-1">
                 <button onClick={() => handleEditStart(pill)} className="text-slate-300 hover:text-teal-600 transition p-1">
                    <Edit2 size={18} />
                 </button>
                 <button onClick={() => handleDelete(pill.id)} className="text-slate-300 hover:text-red-500 transition p-1">
                    <Trash2 size={18} />
                 </button>
              </div>
            </div>
            <div className="space-y-1">
              {pill.ingredients.map((ing, i) => (
                <div key={i} className="text-sm text-slate-600 flex justify-between border-b border-slate-50 last:border-0 py-1">
                  <span>{ing.name}</span>
                  <span className="font-mono text-slate-500">{ing.dosageMg}mg</span>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import { UserData, Pill, LogEntry } from '../types';

const STORAGE_KEY_PREFIX = 'medtrack_user_';
const SESSION_KEY = 'medtrack_last_session_email';

export const loadUserData = (email: string): UserData => {
  const normalizedEmail = email.toLowerCase().trim();
  const key = `${STORAGE_KEY_PREFIX}${normalizedEmail}`;
  const stored = localStorage.getItem(key);

  // Save this email as the active session
  localStorage.setItem(SESSION_KEY, normalizedEmail);

  if (stored) {
    const data = JSON.parse(stored);

    // Data Migration: Convert legacy pillIds to pillsTaken
    if (data.logs) {
      data.logs = data.logs.map((log: any) => {
        if (!log.pillsTaken && log.pillIds) {
          return {
            ...log,
            pillsTaken: log.pillIds.map((id: string) => ({ pillId: id, quantity: 1 })),
          };
        }
        return log;
      });
    }

    return data;
  }
  return {
    email: normalizedEmail,
    pills: [],
    logs: [],
  };
};

export const saveUserData = (data: UserData) => {
  const key = `${STORAGE_KEY_PREFIX}${data.email.toLowerCase().trim()}`;
  localStorage.setItem(key, JSON.stringify(data));
};

export const getLastSessionEmail = (): string | null => {
  return localStorage.getItem(SESSION_KEY);
};

export const clearSession = () => {
  localStorage.removeItem(SESSION_KEY);
};

export const generateId = () => Math.random().toString(36).substring(2, 9);

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, BriefcaseMedical, Bot, Plus, LogOut } from 'lucide-react';
import { Login } from './components/Login';
import { Dashboard } from './components/Dashboard';
import { PillCabinet } from './components/PillCabinet';
import { LogModal } from './components/LogModal';
import { AIAssistant } from './components/AIAssistant';
import { loadUserData, saveUserData, getLastSessionEmail, clearSession } from './services/storage';
import { UserData, AppTab, LogEntry, Pill } from './types';

function App() {
  const [user, setUser] = useState<UserData | null>(null);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [isLogModalOpen, setIsLogModalOpen] = useState(false);
  const [editingLog, setEditingLog] = useState<LogEntry | null>(null);

  // Auto-login on mount
  useEffect(() => {
    const lastEmail = getLastSessionEmail();
    if (lastEmail) {
      const data = loadUserData(lastEmail);
      setUser(data);
    }
  }, []);

  const handleLogin = (email: string) => {
    const data = loadUserData(email);
    setUser(data);
  };

  const handleLogout = () => {
    clearSession();
    setUser(null);
    setActiveTab(AppTab.DASHBOARD);
  };

  // Generic updater for User Data
  const updateUserData = (newData: Partial<UserData>) => {
    if (!user) return;
    const updated = { ...user, ...newData };
    setUser(updated);
    saveUserData(updated);
  };

  const handleUpdatePills = (pills: Pill[]) => {
    updateUserData({ pills });
  };

  const handleSaveLog = (entry: LogEntry) => {
    if (!user) return;

    // Create a fresh copy of the logs array
    let newLogs = [...user.logs];
    const existingIndex = newLogs.findIndex(l => l.id === entry.id);

    if (existingIndex >= 0) {
      newLogs[existingIndex] = entry; // Update existing
    } else {
      newLogs.push(entry); // Create new
    }

    updateUserData({ logs: newLogs });
    // Don't close modal here, let the modal component handle its own closing via prop callback if needed,
    // but typically the modal calls onSave then onClose.
  };

  const handleDeleteLog = (id: string) => {
    if (!user) return;
    // Confirmation handled in UI components usually, but double check here if needed
    // or just execute if the UI component already asked.
    // Since Dashboard asks, we just execute.
    const newLogs = user.logs.filter(l => l.id !== id);
    updateUserData({ logs: newLogs });
    setIsLogModalOpen(false); // Close modal if it was open (e.g. deleting from within edit modal)
  };

  const openLogModal = (entry?: LogEntry) => {
    setEditingLog(entry || null);
    setIsLogModalOpen(true);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-100 font-sans text-slate-900 pb-24 md:pb-0">
      {/* Top Navigation */}
      <header className="bg-white shadow-sm sticky top-0 z-10 border-b border-slate-200">
        <div className="max-w-6xl mx-auto px-4 h-16 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-teal-600 rounded-lg flex items-center justify-center text-white font-bold text-lg">M</div>
            <span className="font-bold text-xl tracking-tight text-slate-800">MedTrack AI</span>
          </div>

          <div className="flex items-center space-x-4">
             <div className="hidden md:block text-sm text-slate-500 mr-2">{user.email}</div>
             <button onClick={handleLogout} className="text-slate-400 hover:text-slate-700 transition" title="Logout">
               <LogOut size={20} />
             </button>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="max-w-6xl mx-auto px-4 py-8">
        <div className="flex justify-between items-center mb-8">
            <h1 className="text-3xl font-bold text-slate-900 capitalize">
                {activeTab === AppTab.DASHBOARD && 'Your Diary'}
                {activeTab === AppTab.CABINET && 'Medication Cabinet'}
                {activeTab === AppTab.ASSISTANT && 'AI Assistant'}
            </h1>

            {activeTab === AppTab.DASHBOARD && (
                <button 
                  onClick={() => openLogModal()} 
                  className="bg-slate-900 hover:bg-slate-800 text-white px-5 py-2.5 rounded-full font-medium shadow-lg hover:shadow-xl transition transform hover:-translate-y-0.5 flex items-center gap-2"
                >
                    <Plus size={20} />
                    <span className="hidden sm:inline">Log Now</span>
                </button>
            )}
        </div>

        {activeTab === AppTab.DASHBOARD && (
          <Dashboard 
            logs={user.logs} 
            pills={user.pills} 
            onEditLog={openLogModal}
            onDeleteLog={handleDeleteLog}
          />
        )}

        {activeTab === AppTab.CABINET && (
          <PillCabinet 
            pills={user.pills} 
            onUpdatePills={handleUpdatePills} 
          />
        )}

        {activeTab === AppTab.ASSISTANT && (
          <div className="max-w-3xl mx-auto">
             <AIAssistant 
                logs={user.logs} 
                pills={user.pills} 
                onAddLog={handleSaveLog} 
             />
          </div>
        )}
      </main>

      {/* Floating Log Button (Mobile Only) */}
      {activeTab === AppTab.DASHBOARD && (
        <button 
          onClick={() => openLogModal()}
          className="md:hidden fixed bottom-24 right-6 w-14 h-14 bg-slate-900 text-white rounded-full shadow-2xl flex items-center justify-center z-20"
        >
          <Plus size={28} />
        </button>
      )}

      {/* Bottom Navigation (Mobile) / Side or Top logic handling */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 md:hidden z-30 pb-safe">
        <div className="flex justify-around items-center h-16">
          <button 
            onClick={() => setActiveTab(AppTab.DASHBOARD)} 
            className={`flex flex-col items-center p-2 ${activeTab === AppTab.DASHBOARD ? 'text-teal-600' : 'text-slate-400'}`}
          >
            <LayoutDashboard size={24} />
            <span className="text-[10px] font-medium mt-1">Diary</span>
