import React, { useState, useEffect } from 'react';
import { X, Calendar, Clock, Minus, Plus, Trash2, Check } from 'lucide-react';
import { Pill, LogEntry, PillTaken } from '../types';
import { generateId } from '../services/storage';

interface LogModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (entry: LogEntry) => void;
  onDelete: (id: string) => void;
  availablePills: Pill[];
  initialEntry?: LogEntry | null;
}

export const LogModal: React.FC<LogModalProps> = ({ isOpen, onClose, onSave, onDelete, availablePills, initialEntry }) => {
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [selectedPills, setSelectedPills] = useState<PillTaken[]>([]);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    if (isOpen) {
      if (initialEntry) {
        // Fix: Use local time components to prevent UTC date shifting
        const d = new Date(initialEntry.timestamp);
        const year = d.getFullYear();
        const month = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        setDate(`${year}-${month}-${day}`);

        const hours = String(d.getHours()).padStart(2, '0');
        const mins = String(d.getMinutes()).padStart(2, '0');
        setTime(`${hours}:${mins}`);

        // CRITICAL: Deep copy the pillsTaken array to prevent mutating the original entry in state
        if (initialEntry.pillsTaken) {
          setSelectedPills(initialEntry.pillsTaken.map(p => ({ ...p })));
        } else if (initialEntry.pillIds) {
          // Legacy migration fallback
          setSelectedPills(initialEntry.pillIds.map(id => ({ pillId: id, quantity: 1 })));
        } else {
          setSelectedPills([]);
        }

        setNotes(initialEntry.notes || '');
      } else {
        // Default to now (Local Time)
        const now = new Date();
        const year = now.getFullYear();
        const month = String(now.getMonth() + 1).padStart(2, '0');
        const day = String(now.getDate()).padStart(2, '0');
        setDate(`${year}-${month}-${day}`);

        const hours = String(now.getHours()).padStart(2, '0');
        const mins = String(now.getMinutes()).padStart(2, '0');
        setTime(`${hours}:${mins}`);

        setSelectedPills([]);
        setNotes('');
      }
    }
  }, [isOpen, initialEntry]);

  if (!isOpen) return null;

  const handleUpdateQuantity = (id: string, delta: number) => {
    const existingIndex = selectedPills.findIndex(p => p.pillId === id);

    // Create a deep copy of the array for safe mutation
    const newPills = selectedPills.map(p => ({ ...p }));

    if (existingIndex >= 0) {
      const newQty = Math.max(0, newPills[existingIndex].quantity + delta);

      if (newQty === 0) {
        // Remove pill if qty goes to 0
        newPills.splice(existingIndex, 1);
      } else {
        newPills[existingIndex].quantity = newQty;
      }
      setSelectedPills(newPills);
    } else if (delta > 0) {
      // Add new pill
      if (selectedPills.length < 5) {
        newPills.push({ pillId: id, quantity: delta });
        setSelectedPills(newPills);
      }
    }
  };

  const handleSubmit = () => {
    if (selectedPills.length === 0) {
      alert("Please select at least one pill.");
      return;
    }

    // Construct timestamp from local date/time inputs
    const timestamp = new Date(`${date}T${time}`).getTime();

    const entry: LogEntry = {
      id: initialEntry?.id || generateId(),
      timestamp,
      pillsTaken: selectedPills,
      pillIds: selectedPills.map(p => p.pillId), // Maintain legacy sync
      notes
    };

    onSave(entry);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden animate-fade-in-up flex flex-col max-h-[90vh]">
        <div className="bg-slate-900 px-6 py-4 flex justify-between items-center text-white shrink-0">
          <h3 className="font-bold text-lg">{initialEntry ? 'Edit Entry' : 'Log Medication'}</h3>
          <button onClick={onClose} className="hover:bg-slate-700 p-1 rounded transition">
            <X size={20} />
          </button>
        </div>

        <div className="p-6 space-y-6 overflow-y-auto">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Date</label>
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input
                  type="date"
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  className="w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                />
              </div>
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Time</label>
              <div className="relative">
                <Clock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input
                  type="time"
                  value={time}
                  onChange={(e) => setTime(e.target.value)}
                  className="w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                />
              </div>
            </div>
          </div>

          <div>
            <div className="flex justify-between items-end mb-2">
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider">Select Pills (Max 5)</label>
              <span className="text-xs text-teal-600">{selectedPills.length}/5 distinct items</span>
            </div>
            <div className="grid grid-cols-1 gap-2 p-1">
              {availablePills.map(pill => {
                const selection = selectedPills.find(p => p.pillId === pill.id);
                const quantity = selection ? selection.quantity : 0;

                return (
                  <div
                    key={pill.id}
                    className={`flex items-center justify-between p-3 rounded-lg border transition ${
                      quantity > 0
                        ? 'border-teal-500 bg-teal-50 ring-1 ring-teal-500' 
                        : 'border-slate-200 bg-white'
                    }`}
                  >
                    <div className="flex items-center flex-1 min-w-0">
                        <div className="w-3 h-3 rounded-full mr-3 shrink-0" style={{ backgroundColor: pill.color }}></div>
                        <span className={`text-sm font-medium truncate ${quantity > 0 ? 'text-teal-900' : 'text-slate-700'}`}>
                            {pill.name}
                        </span>
                    </div>

                    <div className="flex items-center space-x-3 ml-4">
                        {quantity > 0 ? (
                             <div className="flex items-center bg-white rounded-md border border-teal-200 shadow-sm">
                                <button 
                                    onClick={() => handleUpdateQuantity(pill.id, -0.5)}
                                    className="p-1.5 text-teal-700 hover:bg-teal-100 rounded-l-md transition"
                                >
                                    <Minus size={14} />
                                </button>
                                <span className="w-8 text-center text-sm font-bold text-teal-800">{quantity}</span>
                                <button 
                                    onClick={() => handleUpdateQuantity(pill.id, 0.5)}
                                    className="p-1.5 text-teal-700 hover:bg-teal-100 rounded-r-md transition"
                                >
                                    <Plus size={14} />
                                </button>
                             </div>
                        ) : (
                             <button
                                onClick={() => handleUpdateQuantity(pill.id, 1)}
                                disabled={selectedPills.length >= 5}
                                className="px-3 py-1.5 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded text-xs font-semibold uppercase tracking-wide transition disabled:opacity-50"
                             >
                                Add
                             </button>
                        )}
                    </div>
                  </div>
                );
              })}
              {availablePills.length === 0 && (
                <div className="text-center text-sm text-slate-500 py-4 border border-dashed border-slate-300 rounded-lg">
                  No pills configured. Go to Cabinet first.
                </div>
              )}
            </div>
          </div>

          <div>
            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Notes (Optional)</label>
            <textarea
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm h-20 focus:ring-2 focus:ring-teal-500 outline-none resize-none"
              placeholder="How are you feeling?"
            />
          </div>
        </div>

        <div className="bg-slate-50 px-6 py-4 flex justify-between shrink-0">
           <div>
              {initialEntry && (
                  <button 
                    onClick={() => onDelete(initialEntry.id)}
                    className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium transition"
                  >
                    <Trash2 size={16} className="mr-1" />
                    Delete
                  </button>
              )}
           </div>
           <div className="flex">
              <button onClick={onClose} className="mr-3 px-4 py-2 text-slate-600 hover:text-slate-800 text-sm font-medium">Cancel</button>
              <button 
                onClick={handleSubmit} 
                disabled={availablePills.length === 0}
                className="bg-slate-900 text-white px-6 py-2 rounded-lg text-sm font-medium hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm flex items-center"
              >
                {initialEntry ? (
                    <>
                        <Check size={16} className="mr-1" />
                        Update Entry
                    </>
                ) : 'Save Entry'}
              </button>
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, BriefcaseMedical, Bot, Plus, LogOut } from 'lucide-react';
import { Login } from './components/Login';
import { Dashboard } from './components/Dashboard';
import { PillCabinet } from './components/PillCabinet';
import { LogModal } from './components/LogModal';
import { AIAssistant } from './components/AIAssistant';
import { loadUserData, saveUserData, getLastSessionEmail, clearSession } from './services/storage';
import { UserData, AppTab, LogEntry, Pill } from './types';

function App() {
  // CRITICAL FIX: Initialize state lazily. 
  // This checks storage BEFORE the first render, ensuring data is ready immediately.
  // This prevents the "Login" screen from flashing and guarantees data persistence on reload.
  const [user, setUser] = useState<UserData | null>(() => {
    const lastEmail = getLastSessionEmail();
    if (lastEmail) {
      return loadUserData(lastEmail);
    }
    return null;
  });

  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [isLogModalOpen, setIsLogModalOpen] = useState(false);
  const [editingLog, setEditingLog] = useState<LogEntry | null>(null);

  const handleLogin = (email: string) => {
    const data = loadUserData(email);
    setUser(data);
  };

  const handleLogout = () => {
    clearSession();
    setUser(null);
    setActiveTab(AppTab.DASHBOARD);
  };

  // Generic updater for User Data
  const updateUserData = (newData: Partial<UserData>) => {
    if (!user) return;
    const updated = { ...user, ...newData };
    setUser(updated);
    saveUserData(updated);
  };

  const handleUpdatePills = (pills: Pill[]) => {
    updateUserData({ pills });
  };

  const handleSaveLog = (entry: LogEntry) => {
    if (!user) return;

    // Create a fresh copy of the logs array
    let newLogs = [...user.logs];
    const existingIndex = newLogs.findIndex(l => l.id === entry.id);

    if (existingIndex >= 0) {
      newLogs[existingIndex] = entry; // Update existing
    } else {
      newLogs.push(entry); // Create new
    }

    updateUserData({ logs: newLogs });
  };

  const handleDeleteLog = (id: string) => {
    if (!user) return;

    if (window.confirm("Are you sure you want to delete this entry?")) {
      const newLogs = user.logs.filter(l => l.id !== id);
      updateUserData({ logs: newLogs });
      setIsLogModalOpen(false); // Close modal if deleting from within edit view
    }
  };

  const openLogModal = (entry?: LogEntry) => {
    setEditingLog(entry || null);
    setIsLogModalOpen(true);
  };

  const closeLogModal = () => {
    setIsLogModalOpen(false);
    // Short delay to clear state after animation could go here, 
    // but React batching handles the next open correctly usually.
    setTimeout(() => setEditingLog(null), 300);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-100 font-sans text-slate-900 pb-24 md:pb-0">
      {/* Top Navigation */}
      <header className="bg-white shadow-sm sticky top-0 z-10 border-b border-slate-200">
        <div className="max-w-6xl mx-auto px-4 h-16 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-teal-600 rounded-lg flex items-center justify-center text-white font-bold text-lg">M</div>
            <span className="font-bold text-xl tracking-tight text-slate-800">MedTrack AI</span>
          </div>

          <div className="flex items-center space-x-4">
             <div className="hidden md:block text-sm text-slate-500 mr-2">{user.email}</div>
             <button onClick={handleLogout} className="text-slate-400 hover:text-slate-700 transition" title="Logout">
               <LogOut size={20} />
             </button>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="max-w-6xl mx-auto px-4 py-8">
        <div className="flex justify-between items-center mb-8">
            <h1 className="text-3xl font-bold text-slate-900 capitalize">
                {activeTab === AppTab.DASHBOARD && 'Your Diary'}
                {activeTab === AppTab.CABINET && 'Medication Cabinet'}
                {activeTab === AppTab.ASSISTANT && 'AI Assistant'}
            </h1>

            {activeTab === AppTab.DASHBOARD && (
                <button 
                  onClick={() => openLogModal()} 
                  className="bg-slate-900 hover:bg-slate-800 text-white px-5 py-2.5 rounded-full font-medium shadow-lg hover:shadow-xl transition transform hover:-translate-y-0.5 flex items-center gap-2"
                >
                    <Plus size={20} />
                    <span className="hidden sm:inline">Log Now</span>
                </button>
            )}
        </div>

        {activeTab === AppTab.DASHBOARD && (
          <Dashboard 
            logs={user.logs} 
            pills={user.pills} 
            onEditLog={openLogModal}
            onDeleteLog={handleDeleteLog}
          />
        )}

        {activeTab === AppTab.CABINET && (
          <PillCabinet 
            pills={user.pills} 
            onUpdatePills={handleUpdatePills} 
          />
        )}

        {activeTab === AppTab.ASSISTANT && (
          <div className="max-w-3xl mx-auto">
             <AIAssistant 
                logs={user.logs} 
                pills={user.pills} 
                onAddLog={handleSaveLog} 
             />
          </div>
        )}
      </main>

      {/* Floating Log Button (Mobile Only) */}
      {activeTab === AppTab.DASHBOARD && (
        <button 
          onClick={() => openLogModal()}
          className="md:hidden fixed bottom-24 right-6 w-14 h-14 bg-slate-900 text-white rounded-full shadow-2xl flex items-center justify-center z-20"
        >
          <Plus size={28} />
        </button>
      )}

      {/* Bottom Navigation (Mobile) / Side or Top logic handling */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 md:hidden z-30 pb-safe">
        <div className="flex justify-around items-center h-16">
          <button 
            onClick={() => setActiveTab(AppTab.DASHBOARD)} 
            className={`flex flex-col items-center p-2 ${activeTab === AppTab.DASHBOARD ? 'text-teal-600' : 'text-slate-400'}`}
          >
            <LayoutDashboard size={24} />
            <span className="text-[10px] font-medium mt-1">Diary</span>
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.CABINET)} 
            className={`flex flex-col items-center p-2 ${activeTab === AppTab.CABINET ? 'text-teal-600' : 'text-slate-400'}`}
          >
            <BriefcaseMedical size={24} />
            <span className="text-[10px] font-medium mt-1">Cabinet</span>
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.ASSISTANT)} 
            className={`flex flex-col items-center p-2 ${activeTab === AppTab.ASSISTANT ? 'text-teal-600' : 'text-slate-400'}`}
          >
            <Bot size={24} />
            <span className="text-[10px] font-medium mt-1">Assistant</span>
          </button>
        </div>
      </nav>

      {/* Desktop Tabs */}
      <div className="hidden md:flex fixed left-0 top-16 bottom-0 w-20 flex-col items-center py-8 bg-white border-r border-slate-200 z-0">
          <button 
            onClick={() => setActiveTab(AppTab.DASHBOARD)} 
            className={`mb-8 p-3 rounded-xl transition ${activeTab === AppTab.DASHBOARD ? 'bg-teal-50 text-teal-600' : 'text-slate-400 hover:text-slate-600'}`}
            title="Diary"
          >
            <LayoutDashboard size={28} />
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.CABINET)} 
            className={`mb-8 p-3 rounded-xl transition ${activeTab === AppTab.CABINET ? 'bg-teal-50 text-teal-600' : 'text-slate-400 hover:text-slate-600'}`}
            title="Cabinet"
          >
            <BriefcaseMedical size={28} />
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.ASSISTANT)} 
            className={`mb-8 p-3 rounded-xl transition ${activeTab === AppTab.ASSISTANT ? 'bg-teal-50 text-teal-600' : 'text-slate-400 hover:text-slate-600'}`}
            title="AI Assistant"
          >
            <Bot size={28} />
          </button>
      </div>

      <LogModal 
        isOpen={isLogModalOpen} 
        onClose={closeLogModal} 
        onSave={handleSaveLog}
        onDelete={handleDeleteLog}
        availablePills={user.pills}
        initialEntry={editingLog}
      />
    </div>
  );
}

export default App;

import React, { useMemo } from 'react';
import { Edit2, Pill as PillIcon, Calendar as CalendarIcon, Activity, Trash2, ArrowRight } from 'lucide-react';
import { LogEntry, Pill, DailyAggregation } from '../types';

interface DashboardProps {
  logs: LogEntry[];
  pills: Pill[];
  onEditLog: (entry: LogEntry) => void;
  onDeleteLog: (id: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ logs, pills, onEditLog, onDeleteLog }) => {
  const aggregatedData = useMemo(() => {
    const grouped: Record<string, DailyAggregation> = {};

    // Sort logs descending
    const sortedLogs = [...logs].sort((a, b) => b.timestamp - a.timestamp);

    sortedLogs.forEach(log => {
      const dateKey = new Date(log.timestamp).toLocaleDateString('en-CA'); // YYYY-MM-DD

      if (!grouped[dateKey]) {
        grouped[dateKey] = {
          date: dateKey,
          logs: [],
          totalIngredients: {}
        };
      }

      grouped[dateKey].logs.push(log);

      // Aggregate Ingredients
      if (log.pillsTaken) {
        log.pillsTaken.forEach(item => {
          const pill = pills.find(p => p.id === item.pillId);
          if (pill) {
            pill.ingredients.forEach(ing => {
              const current = grouped[dateKey].totalIngredients[ing.name] || 0;
              // Multiply dosage by quantity taken
              grouped[dateKey].totalIngredients[ing.name] = current + (ing.dosageMg * item.quantity);
            });
          }
        });
      }
    });

    return Object.values(grouped).sort((a, b) => b.date.localeCompare(a.date));
  }, [logs, pills]);

  const getPillDetails = (id: string) => pills.find(p => p.id === id);

  if (logs.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-slate-400">
        <Activity size={64} className="mb-4 text-slate-300" />
        <h3 className="text-xl font-bold text-slate-600 mb-2">No logs recorded yet</h3>

        {pills.length === 0 ? (
           <p className="text-sm flex items-center gap-2">
             Go to Cabinet to set up your meds first.
           </p>
        ) : (
           <p className="text-sm">Click "Log Now" to start tracking.</p>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in">
      {aggregatedData.map((day) => (
        <div key={day.date} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          {/* Day Header */}
          <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
            <div className="flex items-center space-x-3">
              <CalendarIcon className="text-teal-600" size={20} />
              <h3 className="font-bold text-lg text-slate-800">
                {new Date(day.date).toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
              </h3>
            </div>
            <div className="text-xs text-slate-500 font-medium px-2 py-1 bg-slate-200 rounded">
              {day.logs.length} Entries
            </div>
          </div>

          <div className="p-6 grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Left: Detailed Timeline */}
            <div className="lg:col-span-2 space-y-4">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Timeline</h4>
              {day.logs.map(log => (
                <div key={log.id} className="relative pl-6 border-l-2 border-slate-200 hover:border-teal-400 transition-colors group">
                  <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-slate-200 group-hover:bg-teal-500 transition-colors"></div>
                  <div className="flex justify-between items-start mb-1">
                    <span className="text-sm font-mono text-slate-500">
                      {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </span>
                    {/* Updated: Buttons are now always visible (opacity removed) for better usability */}
                    <div className="flex items-center space-x-2 bg-white pl-2">
                      <button 
                        onClick={() => onEditLog(log)}
                        className="text-slate-400 hover:text-teal-600 p-1.5 rounded-full hover:bg-teal-50 transition"
                        title="Edit Entry"
                      >
                        <Edit2 size={16} />
                      </button>
                      <button 
                        onClick={() => onDeleteLog(log.id)}
                        className="text-slate-400 hover:text-red-500 p-1.5 rounded-full hover:bg-red-50 transition"
                        title="Delete Entry"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>

                  <div className="flex flex-wrap gap-2 mb-2">
                    {log.pillsTaken?.map((item, idx) => {
                      const pill = getPillDetails(item.pillId);
                      return pill ? (
                        <div key={`${log.id}-${idx}`} className="flex items-center space-x-1 bg-slate-100 px-2 py-1 rounded-full text-xs font-medium text-slate-700 border border-slate-200">
                          <div className="w-2 h-2 rounded-full" style={{ backgroundColor: pill.color }}></div>
                          <span className="font-bold">{item.quantity}x</span>
                          <span>{pill.name}</span>
                        </div>
                      ) : (
                        <span key={idx} className="text-xs text-red-400">Unknown Pill</span>
                      );
                    })}
                  </div>

                  {log.notes && (
                    <p className="text-xs text-slate-500 italic bg-slate-50 p-2 rounded border border-slate-100 inline-block">
                      "{log.notes}"
                    </p>
                  )}
                </div>
              ))}
            </div>

            {/* Right: Ingredient Totals */}
            <div className="bg-slate-50 rounded-xl p-5 h-fit">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center">
                <Activity size={14} className="mr-2" />
                Daily Intake Totals
              </h4>
              <div className="space-y-3">
                {Object.entries(day.totalIngredients).map(([name, total]) => (
                  <div key={name} className="flex justify-between items-center border-b border-slate-200 last:border-0 pb-2 last:pb-0">
                    <span className="text-sm font-medium text-slate-700">{name}</span>
                    <span className="text-sm font-bold text-teal-700">{total} mg</span>
                  </div>
                ))}
                {Object.keys(day.totalIngredients).length === 0 && (
                  <div className="text-sm text-slate-400 italic text-center">No ingredients tracked.</div>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

