import { UserData, AppTab, LogEntry, Pill } from './types';

function App() {
  // CRITICAL FIX: Initialize state lazily. 
  // This checks storage BEFORE the first render, ensuring data is ready immediately.
  // This prevents the "Login" screen from flashing and guarantees data persistence on reload.
  const [user, setUser] = useState<UserData | null>(() => {
    const lastEmail = getLastSessionEmail();
    if (lastEmail) {
      return loadUserData(lastEmail);
    }
    return null;
  });

  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
