    const sortedIngredients = Object.entries(ingredientTotals).sort((a, b) => b[1] - a[1]);

    // Sort logs descending (newest first) for the list view
    const sortedLogs = [...filteredLogs].sort((a, b) => b.timestamp - a.timestamp);

    return {
      totalLogs,
      sortedPills,
      sortedIngredients,
      sortedLogs
    };
  }, [logs, pills, startDate, endDate]);

  const handleQuickRange = (days: number) => {
    const end = new Date();
    const start = new Date();

    // Calculate start date relative to today
    // For "1 Day", we usually mean Today. If we mean "Yesterday and Today", that's 2 days window.
    // Assuming "Last 1 Day" means the last 24h window roughly, or simply Today.
    // Standard interpretation for reports: "Last X Days" includes today.
    // So "Last 1 Day" -> Start = Today, End = Today.
    // "Last 7 Days" -> Start = Today - 6 days, End = Today.

    // Adjust logic: if days=1, subtract 0. If days=7, subtract 6.
    const daysToSubtract = Math.max(0, days - 1);

    start.setDate(end.getDate() - daysToSubtract);

    setEndDate(getLocalDateString(end));
    setStartDate(getLocalDateString(start));
  };

