             <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                <button 
                  onClick={() => handleFontSizeChange('text-base')}
                  className={`p-4 rounded-xl border-2 transition text-center ${fontSize === 'text-base' ? 'border-teal-500 bg-teal-50 text-teal-800' : 'border-slate-200 hover:border-slate-300'}`}
                >
                  <span className="text-base block mb-1 font-medium">Normal</span>
                  <span className="text-xs text-slate-400">1.0 rem</span>
                </button>
                <button 
                  onClick={() => handleFontSizeChange('text-xl')}
                  className={`p-4 rounded-xl border-2 transition text-center ${fontSize === 'text-xl' ? 'border-teal-500 bg-teal-50 text-teal-800' : 'border-slate-200 hover:border-slate-300'}`}
