                <button 
                  onClick={() => handleFontSizeChange('text-2xl')}
                  className={`p-4 rounded-xl border-2 transition text-center ${fontSize === 'text-2xl' ? 'border-teal-500 bg-teal-50 text-teal-800' : 'border-slate-200 hover:border-slate-300'}`}
                >
                  <span className="text-2xl block mb-1 font-medium">Extra Large</span>
                  <span className="text-xs text-slate-400">1.5 rem</span>
                </button>
             </div>
          </div>

          <hr className="border-slate-100" />

          {/* Email Section */}
