}

export enum AppTab {
  DASHBOARD = 'dashboard',
  CABINET = 'cabinet',
  ASSISTANT = 'assistant',
  REPORTS = 'reports',
  SETTINGS = 'settings',
}

import { UserData, Pill, LogEntry } from '../types';

const STORAGE_KEY_PREFIX = 'medtrack_user_';
const SESSION_KEY = 'medtrack_last_session_email';

export const loadUserData = (email: string): UserData => {
  const normalizedEmail = email.toLowerCase().trim();
  const key = `${STORAGE_KEY_PREFIX}${normalizedEmail}`;
  const stored = localStorage.getItem(key);

  // Save this email as the active session
  localStorage.setItem(SESSION_KEY, normalizedEmail);

  if (stored) {
    const data = JSON.parse(stored);

    // Data Migration: Convert legacy pillIds to pillsTaken
    if (data.logs) {
      data.logs = data.logs.map((log: any) => {
        if (!log.pillsTaken && log.pillIds) {
          return {
            ...log,
            pillsTaken: log.pillIds.map((id: string) => ({ pillId: id, quantity: 1 })),
          };
        }
        return log;
      });
    }

    // Settings Migration: Ensure fontSize exists and convert legacy classes to rem
    if (!data.settings) {
      data.settings = { fontSize: '1.25rem' };
    } else {
        // Migration for legacy class names if present
        const legacyMap: Record<string, string> = {
            'text-base': '1rem',
            'text-xl': '1.25rem',
            'text-2xl': '1.5rem'
        };
        if (legacyMap[data.settings.fontSize]) {
            data.settings.fontSize = legacyMap[data.settings.fontSize];
        }
    }

    return data;
  }
  return {
    email: normalizedEmail,
    pills: [],
    logs: [],
    settings: { fontSize: '1.25rem' }, 
  };
};

export const saveUserData = (data: UserData) => {
  const key = `${STORAGE_KEY_PREFIX}${data.email.toLowerCase().trim()}`;
  localStorage.setItem(key, JSON.stringify(data));
  // Ensure session is kept in sync if we save
  localStorage.setItem(SESSION_KEY, data.email.toLowerCase().trim());
};

export const deleteUserData = (email: string) => {
  const key = `${STORAGE_KEY_PREFIX}${email.toLowerCase().trim()}`;
  localStorage.removeItem(key);
};

export const getLastSessionEmail = (): string | null => {
  return localStorage.getItem(SESSION_KEY);
};

export const clearSession = () => {
  localStorage.removeItem(SESSION_KEY);
};

export const generateId = () => Math.random().toString(36).substring(2, 9);

import React, { useState, useEffect } from 'react';
import { Settings as SettingsIcon, Type, Mail, Save, AlertTriangle, Check } from 'lucide-react';
import { UserData } from '../types';

interface SettingsProps {
  user: UserData;
  onUpdateEmail: (newEmail: string) => void;
  onUpdateFontSize: (size: string) => void;
}

export const Settings: React.FC<SettingsProps> = ({ user, onUpdateEmail, onUpdateFontSize }) => {
  const [email, setEmail] = useState(user.email);
  const [fontSize, setFontSize] = useState(user.settings?.fontSize || '1.25rem');
  const [customVal, setCustomVal] = useState('');
  const [isSaved, setIsSaved] = useState(false);

  useEffect(() => {
      // Sync local state if user settings change externally
      if (user.settings?.fontSize) {
          setFontSize(user.settings.fontSize);

          // If the current font size is not one of the presets, populate custom box
          if (!['1.25rem', '1.75rem', '2.25rem'].includes(user.settings.fontSize)) {
              setCustomVal(user.settings.fontSize.replace('rem', ''));
          } else {
              setCustomVal('');
          }
      }
  }, [user.settings?.fontSize]);

  const handleEmailSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (email && email !== user.email) {
      if (window.confirm("Changing your email will migrate your data to the new email address. Are you sure?")) {
        onUpdateEmail(email);
        setIsSaved(true);
        setTimeout(() => setIsSaved(false), 2000);
      }
    }
  };

  const handlePresetChange = (size: string) => {
    setFontSize(size);
    setCustomVal('');
    onUpdateFontSize(size);
  };

  const handleCustomChange = (val: string) => {
      setCustomVal(val);
      if (val && !isNaN(parseFloat(val))) {
          const newSize = `${val}rem`;
          setFontSize(newSize);
          onUpdateFontSize(newSize);
      }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-6 animate-fade-in">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex items-center space-x-2">
          <SettingsIcon className="text-slate-600" size={20} />
          <h3 className="font-bold text-lg text-slate-800">Application Settings</h3>
        </div>

        <div className="p-6 space-y-8">

          {/* Font Size Section */}
          <div className="space-y-4">
             <div className="flex items-center gap-2 mb-2">
                <Type className="text-teal-600" size={20} />
                <h4 className="font-semibold text-slate-800">Base Font Size</h4>
             </div>
             <p className="text-slate-500 text-sm mb-4">
                 Adjust the base scale of the application. This will resize all text including reports and diaries.
             </p>

             <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                <button 
                  onClick={() => handlePresetChange('1.25rem')}
                  className={`p-4 rounded-xl border-2 transition text-center relative ${fontSize === '1.25rem' ? 'border-teal-500 bg-teal-50 text-teal-800' : 'border-slate-200 hover:border-slate-300'}`}
                >
                  {fontSize === '1.25rem' && <div className="absolute top-2 right-2 text-teal-600"><Check size={16}/></div>}
                  <span className="text-xl block mb-1 font-medium">Standard</span>
                  <span className="text-xs text-slate-400">1.25 rem</span>
                </button>
                <button 
                  onClick={() => handlePresetChange('1.75rem')}
                  className={`p-4 rounded-xl border-2 transition text-center relative ${fontSize === '1.75rem' ? 'border-teal-500 bg-teal-50 text-teal-800' : 'border-slate-200 hover:border-slate-300'}`}
                >
                  {fontSize === '1.75rem' && <div className="absolute top-2 right-2 text-teal-600"><Check size={16}/></div>}
                  <span className="text-3xl block mb-1 font-medium">Large</span>
                  <span className="text-xs text-slate-400">1.75 rem</span>
                </button>
                <button 
                  onClick={() => handlePresetChange('2.25rem')}
                  className={`p-4 rounded-xl border-2 transition text-center relative ${fontSize === '2.25rem' ? 'border-teal-500 bg-teal-50 text-teal-800' : 'border-slate-200 hover:border-slate-300'}`}
                >
                  {fontSize === '2.25rem' && <div className="absolute top-2 right-2 text-teal-600"><Check size={16}/></div>}
                  <span className="text-4xl block mb-1 font-medium">Extra Large</span>
                  <span className="text-xs text-slate-400">2.25 rem</span>
                </button>
             </div>

             <div className="mt-4 p-4 bg-slate-50 rounded-xl border border-slate-200">
                 <label className="block text-sm font-semibold text-slate-600 mb-2">Custom Value (rem)</label>
                 <div className="flex items-center gap-2">
                     <input 
                        type="number" 
                        step="0.1"
                        min="0.5"
                        max="5.0"
                        value={customVal}
                        onChange={(e) => handleCustomChange(e.target.value)}
                        placeholder="e.g. 1.5"
                        className="w-32 px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
                     />
                     <span className="text-slate-500 font-medium">rem</span>
                 </div>
                 <p className="text-xs text-slate-400 mt-2">Enter a number to set a custom root font size.</p>
             </div>
          </div>

          <hr className="border-slate-100" />

          {/* Email Section */}
          <form onSubmit={handleEmailSave} className="space-y-4">
             <div className="flex items-center gap-2 mb-2">
                <Mail className="text-indigo-600" size={20} />
                <h4 className="font-semibold text-slate-800">Account Email</h4>
             </div>
             <p className="text-slate-500 text-sm mb-4">
               Update the email address associated with your logs. 
               <span className="flex items-center gap-1 text-orange-500 mt-1">
                 <AlertTriangle size={12} />
                 <span>Warning: This changes your login credential.</span>
               </span>
             </p>

             <div className="flex gap-2">
                <input 
                  type="email" 
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="flex-1 px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                />
                <button 
                  type="submit"
                  disabled={email === user.email}
                  className="px-6 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition flex items-center gap-2"
                >
                  <Save size={18} />
                  Save
                </button>
             </div>
             {isSaved && <p className="text-green-600 text-sm font-medium animate-pulse">Email updated successfully!</p>}
          </form>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, BriefcaseMedical, Bot, Plus, LogOut, Download, BarChart3, Settings as SettingsIcon } from 'lucide-react';
import { Login } from './components/Login';
import { Dashboard } from './components/Dashboard';
import { PillCabinet } from './components/PillCabinet';
import { LogModal } from './components/LogModal';
import { AIAssistant } from './components/AIAssistant';
import { Reports } from './components/Reports';
import { Settings } from './components/Settings';
import { loadUserData, saveUserData, getLastSessionEmail, clearSession, deleteUserData } from './services/storage';
import { UserData, AppTab, LogEntry, Pill } from './types';

function App() {
  const [user, setUser] = useState<UserData | null>(() => {
    const lastEmail = getLastSessionEmail();
    if (lastEmail) {
      return loadUserData(lastEmail);
    }
    return null;
  });

  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [isLogModalOpen, setIsLogModalOpen] = useState(false);
  const [editingLog, setEditingLog] = useState<LogEntry | null>(null);

  // Apply Font Size Global Scaling
  useEffect(() => {
    // Default to 1.25rem if not set
    const size = user?.settings?.fontSize || '1.25rem';
    document.documentElement.style.fontSize = size;
  }, [user?.settings?.fontSize]);

  const handleLogin = (email: string) => {
    const data = loadUserData(email);
    setUser(data);
  };

  const handleLogout = () => {
    clearSession();
    setUser(null);
    setActiveTab(AppTab.DASHBOARD);
    // Reset font size on logout optionally, or keep preference. Keeping it is better UX usually.
  };

  const handleExportData = () => {
    if (!user) return;
    const dataStr = JSON.stringify(user, null, 2);
    const blob = new Blob([dataStr], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `medtrack_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Generic updater for User Data
  const updateUserData = (newData: Partial<UserData>) => {
    if (!user) return;
    const updated = { ...user, ...newData };
    setUser(updated);
    saveUserData(updated);
  };

  const handleUpdatePills = (pills: Pill[]) => {
    updateUserData({ pills });
  };

  const handleUpdateFontSize = (newSize: string) => {
    if(!user) return;
    updateUserData({ settings: { ...user.settings, fontSize: newSize } });
  };

  const handleUpdateEmail = (newEmail: string) => {
    if (!user) return;
    const oldEmail = user.email;
    const updatedUser = { ...user, email: newEmail };

    // 1. Save new data under new key
    saveUserData(updatedUser);

    // 2. Remove old data
    deleteUserData(oldEmail);

    // 3. Update State
    setUser(updatedUser);
  };

  const handleSaveLog = (entry: LogEntry) => {
    if (!user) return;

    // Create a fresh copy of the logs array
    let newLogs = [...user.logs];
    const existingIndex = newLogs.findIndex(l => l.id === entry.id);

    if (existingIndex >= 0) {
      newLogs[existingIndex] = entry; // Update existing
    } else {
      newLogs.push(entry); // Create new
    }

    updateUserData({ logs: newLogs });
  };

  const handleDeleteLog = (id: string) => {
    if (!user) return;

    if (window.confirm("Are you sure you want to delete this entry?")) {
      const newLogs = user.logs.filter(l => l.id !== id);
      updateUserData({ logs: newLogs });
      setIsLogModalOpen(false); // Close modal if deleting from within edit view
    }
  };

  const openLogModal = (entry?: LogEntry) => {
    setEditingLog(entry || null);
    setIsLogModalOpen(true);
  };

  const closeLogModal = () => {
    setIsLogModalOpen(false);
    setTimeout(() => setEditingLog(null), 300);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-100 font-sans text-slate-900 pb-24 md:pb-0">
      {/* Top Navigation */}
      <header className="bg-white shadow-sm sticky top-0 z-10 border-b border-slate-200">
        <div className="max-w-6xl mx-auto px-4 h-16 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-teal-600 rounded-lg flex items-center justify-center text-white font-bold text-lg">M</div>
            <span className="font-bold text-xl tracking-tight text-slate-800">MedTrack AI</span>
          </div>

          <div className="flex items-center space-x-2 md:space-x-4">
             <div className="hidden md:block text-sm text-slate-500 mr-2">{user.email}</div>

             <button 
                onClick={handleExportData} 
                className="text-slate-500 hover:text-teal-600 transition flex items-center gap-1 px-3 py-1 rounded-md hover:bg-slate-100"
                title="Backup Data"
             >
               <Download size={18} />
               <span className="hidden sm:inline text-sm font-medium">Backup</span>
             </button>

             <div className="h-6 w-px bg-slate-200 mx-1"></div>

             <button onClick={handleLogout} className="text-slate-400 hover:text-slate-700 transition p-1" title="Logout">
               <LogOut size={20} />
             </button>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="max-w-6xl mx-auto px-4 py-8 pl-4 md:pl-24">
        <div className="flex justify-between items-center mb-8">
            <h1 className="text-3xl font-bold text-slate-900 capitalize">
                {activeTab === AppTab.DASHBOARD && 'Your Diary'}
                {activeTab === AppTab.CABINET && 'Medication Cabinet'}
                {activeTab === AppTab.ASSISTANT && 'AI Assistant'}
                {activeTab === AppTab.REPORTS && 'Reports & Analytics'}
                {activeTab === AppTab.SETTINGS && 'Settings'}
            </h1>

            {activeTab === AppTab.DASHBOARD && (
                <button 
                  onClick={() => openLogModal()} 
                  className="bg-slate-900 hover:bg-slate-800 text-white px-5 py-2.5 rounded-full font-medium shadow-lg hover:shadow-xl transition transform hover:-translate-y-0.5 flex items-center gap-2"
                >
                    <Plus size={20} />
                    <span className="hidden sm:inline">Log Now</span>
                </button>
            )}
        </div>

        {activeTab === AppTab.DASHBOARD && (
          <Dashboard 
            logs={user.logs} 
            pills={user.pills} 
            onEditLog={openLogModal}
            onDeleteLog={handleDeleteLog}
          />
        )}

        {activeTab === AppTab.CABINET && (
          <PillCabinet 
            pills={user.pills} 
            onUpdatePills={handleUpdatePills} 
          />
        )}

        {activeTab === AppTab.ASSISTANT && (
          <div className="max-w-3xl mx-auto">
             <AIAssistant 
                logs={user.logs} 
                pills={user.pills} 
                onAddLog={handleSaveLog} 
             />
          </div>
        )}

        {activeTab === AppTab.REPORTS && (
          <div className="max-w-4xl mx-auto">
             <Reports 
                logs={user.logs} 
                pills={user.pills} 
             />
          </div>
        )}

        {activeTab === AppTab.SETTINGS && (
           <div className="max-w-4xl mx-auto">
              <Settings 
                user={user}
                onUpdateEmail={handleUpdateEmail}
                onUpdateFontSize={handleUpdateFontSize}
              />
           </div>
        )}
      </main>

      {/* Floating Log Button (Mobile Only) */}
      {activeTab === AppTab.DASHBOARD && (
        <button 
          onClick={() => openLogModal()}
          className="md:hidden fixed bottom-24 right-6 w-14 h-14 bg-slate-900 text-white rounded-full shadow-2xl flex items-center justify-center z-20"
        >
          <Plus size={28} />
        </button>
      )}

      {/* Bottom Navigation (Mobile) */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 md:hidden z-30 pb-safe">
        <div className="flex justify-around items-center h-16">
          <button 
            onClick={() => setActiveTab(AppTab.DASHBOARD)} 
            className={`flex flex-col items-center p-2 ${activeTab === AppTab.DASHBOARD ? 'text-teal-600' : 'text-slate-400'}`}
          >
            <LayoutDashboard size={24} />
            <span className="text-[10px] font-medium mt-1">Diary</span>
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.CABINET)} 
            className={`flex flex-col items-center p-2 ${activeTab === AppTab.CABINET ? 'text-teal-600' : 'text-slate-400'}`}
          >
            <BriefcaseMedical size={24} />
            <span className="text-[10px] font-medium mt-1">Cabinet</span>
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.REPORTS)} 
            className={`flex flex-col items-center p-2 ${activeTab === AppTab.REPORTS ? 'text-teal-600' : 'text-slate-400'}`}
          >
            <BarChart3 size={24} />
            <span className="text-[10px] font-medium mt-1">Reports</span>
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.SETTINGS)} 
            className={`flex flex-col items-center p-2 ${activeTab === AppTab.SETTINGS ? 'text-teal-600' : 'text-slate-400'}`}
          >
            <SettingsIcon size={24} />
            <span className="text-[10px] font-medium mt-1">Settings</span>
          </button>
        </div>
      </nav>

      {/* Desktop Tabs */}
      <div className="hidden md:flex fixed left-0 top-16 bottom-0 w-20 flex-col items-center py-8 bg-white border-r border-slate-200 z-0">
          <button 
            onClick={() => setActiveTab(AppTab.DASHBOARD)} 
            className={`mb-8 p-3 rounded-xl transition ${activeTab === AppTab.DASHBOARD ? 'bg-teal-50 text-teal-600' : 'text-slate-400 hover:text-slate-600'}`}
            title="Diary"
          >
            <LayoutDashboard size={28} />
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.CABINET)} 
            className={`mb-8 p-3 rounded-xl transition ${activeTab === AppTab.CABINET ? 'bg-teal-50 text-teal-600' : 'text-slate-400 hover:text-slate-600'}`}
            title="Cabinet"
          >
            <BriefcaseMedical size={28} />
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.REPORTS)} 
            className={`mb-8 p-3 rounded-xl transition ${activeTab === AppTab.REPORTS ? 'bg-teal-50 text-teal-600' : 'text-slate-400 hover:text-slate-600'}`}
            title="Reports"
          >
            <BarChart3 size={28} />
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.ASSISTANT)} 
            className={`mb-8 p-3 rounded-xl transition ${activeTab === AppTab.ASSISTANT ? 'bg-teal-50 text-teal-600' : 'text-slate-400 hover:text-slate-600'}`}
