}

export default App;

import React, { useState, useMemo } from 'react';
import { Filter, PieChart, Activity, AlertCircle, Clock, CalendarDays, History, Search } from 'lucide-react';
import { LogEntry, Pill } from '../types';

interface ReportsProps {
  logs: LogEntry[];
  pills: Pill[];
}

export const Reports: React.FC<ReportsProps> = ({ logs, pills }) => {
  // Helper: Get local date string YYYY-MM-DD
  const getLocalDateString = (date: Date) => {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  // Default to Last 7 Days
  const [startDate, setStartDate] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() - 7);
    return getLocalDateString(d);
  });

  const [endDate, setEndDate] = useState(() => getLocalDateString(new Date()));
  const [selectedPillId, setSelectedPillId] = useState<string>('all');

  const reportData = useMemo(() => {
    // Manually parse strings to create Local Date objects
    const [sy, sm, sd] = startDate.split('-').map(Number);
    const start = new Date(sy, sm - 1, sd, 0, 0, 0, 0);

    const [ey, em, ed] = endDate.split('-').map(Number);
    const end = new Date(ey, em - 1, ed, 23, 59, 59, 999);

    // Calculate days in range (inclusive)
    const daysDiff = Math.max(1, Math.round((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)));

    const filteredLogs = logs.filter(log => {
      const logDate = new Date(log.timestamp);
      return logDate.getTime() >= start.getTime() && logDate.getTime() <= end.getTime();
    });

    // Aggregations
    const pillCounts: Record<string, number> = {};
    const ingredientTotals: Record<string, number> = {};
    const totalLogs = filteredLogs.length;

    // Drill down data
    const specificPillLogs: { log: LogEntry; quantity: number }[] = [];

    filteredLogs.forEach(log => {
      if (log.pillsTaken) {
        log.pillsTaken.forEach(item => {
          const pill = pills.find(p => p.id === item.pillId);
          if (pill) {
            // Count Pills
            pillCounts[pill.name] = (pillCounts[pill.name] || 0) + item.quantity;

            // Sum Ingredients
            pill.ingredients.forEach(ing => {
              ingredientTotals[ing.name] = (ingredientTotals[ing.name] || 0) + (ing.dosageMg * item.quantity);
            });

            // Drill down check
            if (pill.id === selectedPillId) {
                specificPillLogs.push({ log, quantity: item.quantity });
            }
          }
        });
      }
    });

    // Sort for display
    const sortedPills = Object.entries(pillCounts).sort((a, b) => b[1] - a[1]);
    const sortedIngredients = Object.entries(ingredientTotals).sort((a, b) => b[1] - a[1]);

    // Sort logs descending
    const sortedLogs = [...filteredLogs].sort((a, b) => b.timestamp - a.timestamp);
    const sortedSpecificLogs = specificPillLogs.sort((a, b) => b.log.timestamp - a.log.timestamp);

    const totalSpecificQuantity = specificPillLogs.reduce((acc, curr) => acc + curr.quantity, 0);

    return {
      totalLogs,
      sortedPills,
      sortedIngredients,
      sortedLogs,
      sortedSpecificLogs,
      totalSpecificQuantity,
      daysDiff
    };
  }, [logs, pills, startDate, endDate, selectedPillId]);

  const handleQuickRange = (days: number) => {
    const end = new Date();
    const start = new Date();
    const daysToSubtract = Math.max(0, days - 1);
    start.setDate(end.getDate() - daysToSubtract);

    setEndDate(getLocalDateString(end));
    setStartDate(getLocalDateString(start));
  };

  const getTimeAgo = (timestamp: number) => {
    const seconds = Math.floor((Date.now() - timestamp) / 1000);
    if (seconds < 60) return 'Just now';
    const minutes = Math.floor(seconds / 60);
    if (minutes < 60) return `${minutes} min ago`;
    const hours = Math.floor(minutes / 60);
    if (hours < 24) return `${hours} hr${hours > 1 ? 's' : ''} ago`;
    const days = Math.floor(hours / 24);
    if (days < 30) return `${days} day${days > 1 ? 's' : ''} ago`;
    const months = Math.floor(days / 30);
    return `${months} mo${months > 1 ? 's' : ''} ago`;
  };

  const formatLogDate = (timestamp: number) => {
      return new Date(timestamp).toLocaleString(undefined, {
          weekday: 'short',
          month: 'short',
          day: 'numeric',
          hour: 'numeric',
          minute: '2-digit'
      });
  };

  return (
    <div className="space-y-6 animate-fade-in pb-12">
      {/* Controls */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
         <div className="flex flex-col md:flex-row md:items-end gap-4 mb-4">
            <div className="flex-1">
                <label className="block text-sm font-semibold text-slate-500 uppercase tracking-wider mb-2">From</label>
                <input 
                    type="date" 
                    value={startDate} 
                    onChange={(e) => setStartDate(e.target.value)}
                    className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                />
            </div>
            <div className="flex-1">
                <label className="block text-sm font-semibold text-slate-500 uppercase tracking-wider mb-2">To</label>
                <input 
                    type="date" 
                    value={endDate} 
                    onChange={(e) => setEndDate(e.target.value)}
                    className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                />
            </div>
         </div>

         <div className="mb-4">
             <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Quick Select Days</label>
             <div className="flex flex-wrap gap-2">
                {[1, 2, 3, 4, 5].map(days => (
                    <button 
                        key={days}
                        onClick={() => handleQuickRange(days)} 
                        className="px-3 py-1.5 text-sm font-medium bg-slate-50 hover:bg-teal-50 text-slate-600 hover:text-teal-700 border border-slate-200 rounded-lg transition"
                    >
                        Last {days} {days === 1 ? 'Day' : 'Days'}
                    </button>
                ))}
                <div className="w-px bg-slate-200 mx-1 h-6 self-center"></div>
                <button onClick={() => handleQuickRange(7)} className="px-3 py-1.5 text-sm font-medium bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg transition">Last 7</button>
                <button onClick={() => handleQuickRange(30)} className="px-3 py-1.5 text-sm font-medium bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg transition">Last 30</button>
             </div>
         </div>

         <div className="text-xs text-slate-400 flex items-center pt-2 border-t border-slate-50">
            <Filter size={12} className="mr-1" />
            Showing data for {reportData.totalLogs} entries found in this range.
         </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-80 overflow-y-auto">
             <div className="flex items-center space-x-2 mb-6 pb-4 border-b border-slate-100 sticky top-0 bg-white z-10">
                <PieChart className="text-teal-600" size={20} />
                <h3 className="font-bold text-lg text-slate-800">Pill Counts</h3>
             </div>
             {reportData.sortedPills.length > 0 ? (
                 <div className="space-y-4">
                    {reportData.sortedPills.map(([name, count]) => (
                        <div key={name} className="flex items-center justify-between">
                            <span className="text-slate-700 font-medium">{name}</span>
                            <div className="flex items-center">
                                <div className="h-2 bg-slate-100 w-24 rounded-full mr-3 overflow-hidden">
                                    <div className="h-full bg-teal-500 rounded-full" style={{ width: `${Math.min(100, (count / reportData.sortedPills[0][1]) * 100)}%` }}></div>
                                </div>
                                <span className="text-sm font-bold text-slate-900 w-8 text-right">{count}</span>
                            </div>
                        </div>
                    ))}
                 </div>
             ) : (
                <div className="text-center py-8 text-slate-400 flex flex-col items-center">
                    <AlertCircle size={32} className="mb-2 opacity-50" />
                    <p>No pills taken in this range.</p>
                </div>
             )}
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-80 overflow-y-auto">
             <div className="flex items-center space-x-2 mb-6 pb-4 border-b border-slate-100 sticky top-0 bg-white z-10">
                <Activity className="text-indigo-600" size={20} />
                <h3 className="font-bold text-lg text-slate-800">Total Ingredients</h3>
             </div>
             {reportData.sortedIngredients.length > 0 ? (
                 <div className="space-y-4">
                    {reportData.sortedIngredients.map(([name, total]) => (
                        <div key={name} className="flex flex-col sm:flex-row sm:justify-between sm:items-center py-1">
                            <span className="text-slate-700 font-medium mb-1 sm:mb-0">{name}</span>
                            <span className="text-sm font-bold text-indigo-700 bg-indigo-50 px-3 py-1 rounded-full">{total} mg</span>
                        </div>
                    ))}
                 </div>
             ) : (
                <div className="text-center py-8 text-slate-400 flex flex-col items-center">
                    <AlertCircle size={32} className="mb-2 opacity-50" />
                    <p>No ingredients tracked.</p>
                </div>
             )}
          </div>
      </div>

      {/* Specific Pill Drill-Down */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="bg-slate-50 px-6 py-4 border-b border-slate-200">
              <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                <div className="flex items-center space-x-2">
                    <Search className="text-purple-600" size={20} />
                    <h3 className="font-bold text-lg text-slate-800">Specific Pill Analysis</h3>
                </div>
                <select 
                    value={selectedPillId}
                    onChange={(e) => setSelectedPillId(e.target.value)}
                    className="px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-purple-500 outline-none text-sm min-w-[200px]"
                >
                    <option value="all">Select a pill...</option>
                    {pills.map(p => (
                        <option key={p.id} value={p.id}>{p.name}</option>
                    ))}
                </select>
              </div>
          </div>

          {selectedPillId !== 'all' ? (
              <div className="p-6">
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
                      <div className="bg-purple-50 p-4 rounded-xl border border-purple-100">
                          <p className="text-xs text-slate-500 uppercase tracking-wide font-semibold">Total Qty</p>
                          <p className="text-2xl font-bold text-purple-700 mt-1">
                              {reportData.totalSpecificQuantity}
                          </p>
                      </div>
                      <div className="bg-purple-50 p-4 rounded-xl border border-purple-100">
                          <p className="text-xs text-slate-500 uppercase tracking-wide font-semibold">Times Taken</p>
                          <p className="text-2xl font-bold text-slate-700 mt-1">
                              {reportData.sortedSpecificLogs.length}
                          </p>
                      </div>
                      <div className="bg-purple-50 p-4 rounded-xl border border-purple-100">
                          <p className="text-xs text-slate-500 uppercase tracking-wide font-semibold">Avg / Dose</p>
                          <p className="text-2xl font-bold text-teal-600 mt-1">
                              {reportData.sortedSpecificLogs.length ? (reportData.totalSpecificQuantity / reportData.sortedSpecificLogs.length).toFixed(1) : 0}
                          </p>
                      </div>
                      <div className="bg-purple-50 p-4 rounded-xl border border-purple-100">
                          <p className="text-xs text-slate-500 uppercase tracking-wide font-semibold">Avg / Day</p>
                          <p className="text-2xl font-bold text-indigo-600 mt-1">
                              {(reportData.totalSpecificQuantity / reportData.daysDiff).toFixed(1)}
                          </p>
                      </div>
                  </div>

                  <h4 className="text-sm font-semibold text-slate-500 mb-3">Usage History</h4>
                  {reportData.sortedSpecificLogs.length > 0 ? (
                    <div className="space-y-3">
                        {reportData.sortedSpecificLogs.map((item, idx) => (
                            <div key={`${item.log.id}-${idx}`} className="flex items-center justify-between p-3 bg-white border border-slate-100 rounded-lg hover:border-purple-200 transition">
                                <div className="flex items-center gap-3">
                                    <div className="w-2 h-2 rounded-full bg-purple-400"></div>
                                    <span className="font-medium text-slate-800">{formatLogDate(item.log.timestamp)}</span>
                                </div>
                                <div className="flex items-center gap-4">
                                    <span className="text-sm text-slate-500">{getTimeAgo(item.log.timestamp)}</span>
                                    <span className="px-2 py-1 bg-purple-100 text-purple-800 text-xs font-bold rounded-md">{item.quantity}x</span>
                                </div>
                            </div>
                        ))}
                    </div>
                  ) : (
                    <p className="text-slate-400 italic">No usage found in selected date range.</p>
                  )}
              </div>
          ) : (
              <div className="p-8 text-center text-slate-400">
                  <p>Select a pill from the dropdown above to see detailed breakdown.</p>
              </div>
          )}
      </div>

      {/* Detailed Log History Table */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex items-center space-x-2">
            <History className="text-slate-600" size={20} />
            <h3 className="font-bold text-lg text-slate-800">Full History</h3>
        </div>

        {reportData.sortedLogs.length > 0 ? (
            <div className="divide-y divide-slate-100">
                {reportData.sortedLogs.map(log => (
                    <div key={log.id} className="p-4 hover:bg-slate-50 transition flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2">
                        {/* Left: Date and Time */}
                        <div className="flex items-start sm:items-center gap-3 min-w-[200px]">
                            <div className="p-2 bg-slate-100 rounded-lg text-slate-500">
                                <CalendarDays size={18} />
                            </div>
                            <div>
                                <p className="text-sm font-bold text-slate-800">{formatLogDate(log.timestamp)}</p>
                                <p className="text-xs text-teal-600 font-medium flex items-center mt-0.5">
                                    <Clock size={10} className="mr-1" />
                                    {getTimeAgo(log.timestamp)}
                                </p>
                            </div>
                        </div>

                        {/* Middle: Pills */}
                        <div className="flex-1">
                             <div className="flex flex-wrap gap-2">
                                {log.pillsTaken?.map((item, idx) => {
                                    const pill = pills.find(p => p.id === item.pillId);
                                    return (
                                        <span key={idx} className="inline-flex items-center px-2.5 py-1 rounded-full text-xs font-medium bg-indigo-50 text-indigo-700 border border-indigo-100">
                                            {item.quantity}x {pill ? pill.name : 'Unknown'}
                                        </span>
                                    );
                                })}
                             </div>
                             {log.notes && (
                                <p className="text-xs text-slate-400 italic mt-1 pl-1">"{log.notes}"</p>
                             )}
                        </div>
                    </div>
                ))}
            </div>
        ) : (
            <div className="p-12 text-center text-slate-400">
                No detailed logs found for this period.
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { Edit2, Pill as PillIcon, Calendar as CalendarIcon, Activity, Trash2, ArrowRight } from 'lucide-react';
import { LogEntry, Pill, DailyAggregation } from '../types';

interface DashboardProps {
  logs: LogEntry[];
  pills: Pill[];
  onEditLog: (entry: LogEntry) => void;
  onDeleteLog: (id: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ logs, pills, onEditLog, onDeleteLog }) => {
  const aggregatedData = useMemo(() => {
    const grouped: Record<string, DailyAggregation> = {};

    // Sort logs descending
    const sortedLogs = [...logs].sort((a, b) => b.timestamp - a.timestamp);

    sortedLogs.forEach(log => {
      const dateKey = new Date(log.timestamp).toLocaleDateString('en-CA'); // YYYY-MM-DD

      if (!grouped[dateKey]) {
        grouped[dateKey] = {
          date: dateKey,
          logs: [],
          totalIngredients: {}
        };
      }

      grouped[dateKey].logs.push(log);

      // Aggregate Ingredients
      if (log.pillsTaken) {
        log.pillsTaken.forEach(item => {
          const pill = pills.find(p => p.id === item.pillId);
          if (pill) {
            pill.ingredients.forEach(ing => {
              const current = grouped[dateKey].totalIngredients[ing.name] || 0;
              // Multiply dosage by quantity taken
              grouped[dateKey].totalIngredients[ing.name] = current + (ing.dosageMg * item.quantity);
            });
          }
        });
      }
    });

    return Object.values(grouped).sort((a, b) => b.date.localeCompare(a.date));
  }, [logs, pills]);

  const getPillDetails = (id: string) => pills.find(p => p.id === id);

  // Helper to safely format YYYY-MM-DD string to a Local Date String
  const formatHeaderDate = (dateStr: string) => {
    // Manually parse YYYY-MM-DD to ensure we treat it as LOCAL time, not UTC.
    // new Date("2025-12-09") creates UTC midnight, which displays as Dec 8th in US timezones.
    const [year, month, day] = dateStr.split('-').map(Number);
    const localDate = new Date(year, month - 1, day); 

    return localDate.toLocaleDateString(undefined, { 
        weekday: 'long', 
        year: 'numeric', 
        month: 'long', 
        day: 'numeric' 
    });
  };

  if (logs.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-slate-400">
        <Activity size={64} className="mb-4 text-slate-300" />
        <h3 className="text-xl font-bold text-slate-600 mb-2">No logs recorded yet</h3>

        {pills.length === 0 ? (
           <p className="text-sm flex items-center gap-2">
             Go to Cabinet to set up your meds first.
           </p>
        ) : (
           <p className="text-sm">Click "Log Now" to start tracking.</p>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in">
      {aggregatedData.map((day) => (
        <div key={day.date} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          {/* Day Header */}
          <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
            <div className="flex items-center space-x-3">
              <CalendarIcon className="text-teal-600" size={20} />
              <h3 className="font-bold text-lg text-slate-800">
                {formatHeaderDate(day.date)}
              </h3>
            </div>
            <div className="text-xs text-slate-500 font-medium px-2 py-1 bg-slate-200 rounded">
              {day.logs.length} Entries
            </div>
          </div>

          <div className="p-6 grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Left: Detailed Timeline */}
            <div className="lg:col-span-2 space-y-4">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Timeline</h4>
              {day.logs.map(log => (
                <div key={log.id} className="relative pl-6 border-l-2 border-slate-200 hover:border-teal-400 transition-colors group">
                  <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-slate-200 group-hover:bg-teal-500 transition-colors"></div>
                  <div className="flex justify-between items-start mb-1">
                    <span className="text-sm font-mono text-slate-500">
                      {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </span>
                    {/* Buttons always visible */}
                    <div className="flex items-center space-x-2 bg-white pl-2">
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onEditLog(log); }}
                        className="text-slate-400 hover:text-teal-600 p-1.5 rounded-full hover:bg-teal-50 transition"
                        title="Edit Entry"
                      >
                        <Edit2 size={16} />
                      </button>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); onDeleteLog(log.id); }}
                        className="text-slate-400 hover:text-red-500 p-1.5 rounded-full hover:bg-red-50 transition"
                        title="Delete Entry"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>

                  <div className="flex flex-wrap gap-2 mb-2">
                    {log.pillsTaken?.map((item, idx) => {
                      const pill = getPillDetails(item.pillId);
                      return pill ? (
                        <div key={`${log.id}-${idx}`} className="flex items-center space-x-1 bg-slate-100 px-2 py-1 rounded-full text-xs font-medium text-slate-700 border border-slate-200">
                          <div className="w-2 h-2 rounded-full" style={{ backgroundColor: pill.color }}></div>
                          <span className="font-bold">{item.quantity}x</span>
                          <span>{pill.name}</span>
                        </div>
                      ) : (
                        <span key={idx} className="text-xs text-red-400">Unknown Pill</span>
                      );
                    })}
                  </div>

                  {log.notes && (
                    <p className="text-xs text-slate-500 italic bg-slate-50 p-2 rounded border border-slate-100 inline-block">
                      "{log.notes}"
                    </p>
                  )}
                </div>
              ))}
            </div>

            {/* Right: Ingredient Totals */}
            <div className="bg-slate-50 rounded-xl p-5 h-fit">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center">
                <Activity size={14} className="mr-2" />
                Daily Intake Totals
              </h4>
              <div className="space-y-3">
                {Object.entries(day.totalIngredients).map(([name, total]) => (
                  <div key={name} className="flex justify-between items-center border-b border-slate-200 last:border-0 pb-2 last:pb-0">
                    <span className="text-sm font-medium text-slate-700">{name}</span>
                    <span className="text-sm font-bold text-teal-700">{total} mg</span>
                  </div>
                ))}
                {Object.keys(day.totalIngredients).length === 0 && (
                  <div className="text-sm text-slate-400 italic text-center">No ingredients tracked.</div>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Calendar, Clock, Minus, Plus, Trash2, Check } from 'lucide-react';
import { Pill, LogEntry, PillTaken } from '../types';
import { generateId } from '../services/storage';

interface LogModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (entry: LogEntry) => void;
  onDelete: (id: string) => void;
  availablePills: Pill[];
  initialEntry?: LogEntry | null;
}

export const LogModal: React.FC<LogModalProps> = ({ isOpen, onClose, onSave, onDelete, availablePills, initialEntry }) => {
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [selectedPills, setSelectedPills] = useState<PillTaken[]>([]);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    if (isOpen) {
      if (initialEntry) {
        // Use local time components explicitly to prevent UTC shifting
        const d = new Date(initialEntry.timestamp);
        const year = d.getFullYear();
        const month = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        setDate(`${year}-${month}-${day}`);

        const hours = String(d.getHours()).padStart(2, '0');
        const mins = String(d.getMinutes()).padStart(2, '0');
        setTime(`${hours}:${mins}`);

        // Deep copy the pillsTaken array
        if (initialEntry.pillsTaken) {
          setSelectedPills(initialEntry.pillsTaken.map(p => ({ ...p })));
        } else if (initialEntry.pillIds) {
          setSelectedPills(initialEntry.pillIds.map(id => ({ pillId: id, quantity: 1 })));
        } else {
          setSelectedPills([]);
        }

        setNotes(initialEntry.notes || '');
      } else {
        // Default to now (Local Time)
        const now = new Date();
        const year = now.getFullYear();
        const month = String(now.getMonth() + 1).padStart(2, '0');
        const day = String(now.getDate()).padStart(2, '0');
        setDate(`${year}-${month}-${day}`);

        const hours = String(now.getHours()).padStart(2, '0');
        const mins = String(now.getMinutes()).padStart(2, '0');
        setTime(`${hours}:${mins}`);

        setSelectedPills([]);
        setNotes('');
      }
    }
  }, [isOpen, initialEntry]);

  if (!isOpen) return null;

  const handleUpdateQuantity = (id: string, delta: number) => {
    const existingIndex = selectedPills.findIndex(p => p.pillId === id);
    const newPills = selectedPills.map(p => ({ ...p }));

    if (existingIndex >= 0) {
      const newQty = Math.max(0, newPills[existingIndex].quantity + delta);
      if (newQty === 0) {
        newPills.splice(existingIndex, 1);
      } else {
        newPills[existingIndex].quantity = newQty;
      }
      setSelectedPills(newPills);
    } else if (delta > 0) {
      if (selectedPills.length < 5) {
        newPills.push({ pillId: id, quantity: delta });
        setSelectedPills(newPills);
      }
    }
  };

  const handleSubmit = () => {
    if (selectedPills.length === 0) {
      alert("Please select at least one pill.");
      return;
    }

    // CRITICAL FIX: Explicitly parse date components to avoid Timezone issues.
    // Creating a date from string "YYYY-MM-DDTHH:MM" can sometimes be interpreted 
    // strangely by different browsers or if formatting is slightly off.
    // We strictly use Local Time here.
    const [year, month, day] = date.split('-').map(Number);
    const [hours, minutes] = time.split(':').map(Number);

    // Note: Month is 0-indexed in JS Date constructor (0 = Jan, 11 = Dec)
    const timestamp = new Date(year, month - 1, day, hours, minutes).getTime();

    const entry: LogEntry = {
      id: initialEntry?.id || generateId(),
      timestamp,
      pillsTaken: selectedPills,
      pillIds: selectedPills.map(p => p.pillId),
      notes
    };

    onSave(entry);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden animate-fade-in-up flex flex-col max-h-[90vh]">
        <div className="bg-slate-900 px-6 py-4 flex justify-between items-center text-white shrink-0">
          <h3 className="font-bold text-lg">{initialEntry ? 'Edit Entry' : 'Log Medication'}</h3>
          <button onClick={onClose} className="hover:bg-slate-700 p-1 rounded transition">
            <X size={20} />
          </button>
        </div>

        <div className="p-6 space-y-6 overflow-y-auto">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Date</label>
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input
                  type="date"
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  className="w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                />
              </div>
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Time</label>
              <div className="relative">
                <Clock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input
                  type="time"
                  value={time}
                  onChange={(e) => setTime(e.target.value)}
                  className="w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                />
              </div>
            </div>
          </div>

          <div>
            <div className="flex justify-between items-end mb-2">
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider">Select Pills (Max 5)</label>
              <span className="text-xs text-teal-600">{selectedPills.length}/5 distinct items</span>
            </div>
            <div className="grid grid-cols-1 gap-2 p-1">
              {availablePills.map(pill => {
                const selection = selectedPills.find(p => p.pillId === pill.id);
                const quantity = selection ? selection.quantity : 0;

                return (
                  <div
                    key={pill.id}
                    className={`flex items-center justify-between p-3 rounded-lg border transition ${
                      quantity > 0
                        ? 'border-teal-500 bg-teal-50 ring-1 ring-teal-500' 
                        : 'border-slate-200 bg-white'
                    }`}
                  >
                    <div className="flex items-center flex-1 min-w-0">
                        <div className="w-3 h-3 rounded-full mr-3 shrink-0" style={{ backgroundColor: pill.color }}></div>
                        <span className={`text-sm font-medium truncate ${quantity > 0 ? 'text-teal-900' : 'text-slate-700'}`}>
                            {pill.name}
                        </span>
                    </div>

                    <div className="flex items-center space-x-3 ml-4">
                        {quantity > 0 ? (
                             <div className="flex items-center bg-white rounded-md border border-teal-200 shadow-sm">
                                <button 
                                    onClick={() => handleUpdateQuantity(pill.id, -0.5)}
                                    className="p-1.5 text-teal-700 hover:bg-teal-100 rounded-l-md transition"
                                >
                                    <Minus size={14} />
                                </button>
                                <span className="w-8 text-center text-sm font-bold text-teal-800">{quantity}</span>
                                <button 
                                    onClick={() => handleUpdateQuantity(pill.id, 0.5)}
                                    className="p-1.5 text-teal-700 hover:bg-teal-100 rounded-r-md transition"
                                >
                                    <Plus size={14} />
                                </button>
                             </div>
                        ) : (
                             <button
                                onClick={() => handleUpdateQuantity(pill.id, 1)}
                                disabled={selectedPills.length >= 5}
                                className="px-3 py-1.5 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded text-xs font-semibold uppercase tracking-wide transition disabled:opacity-50"
                             >
                                Add
                             </button>
                        )}
                    </div>
                  </div>
                );
              })}
              {availablePills.length === 0 && (
                <div className="text-center text-sm text-slate-500 py-4 border border-dashed border-slate-300 rounded-lg">
                  No pills configured. Go to Cabinet first.
                </div>
              )}
            </div>
          </div>

          <div>
            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Notes (Optional)</label>
            <textarea
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm h-20 focus:ring-2 focus:ring-teal-500 outline-none resize-none"
              placeholder="How are you feeling?"
            />
          </div>
        </div>

        <div className="bg-slate-50 px-6 py-4 flex justify-between shrink-0">
           <div>
              {initialEntry && (
                  <button 
                    type="button"
                    onClick={() => onDelete(initialEntry.id)}
                    className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium transition"
                  >
                    <Trash2 size={16} className="mr-1" />
                    Delete
                  </button>
              )}
           </div>
           <div className="flex">
              <button onClick={onClose} className="mr-3 px-4 py-2 text-slate-600 hover:text-slate-800 text-sm font-medium">Cancel</button>
              <button 
                onClick={handleSubmit} 
                disabled={availablePills.length === 0}
                className="bg-slate-900 text-white px-6 py-2 rounded-lg text-sm font-medium hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm flex items-center"
              >
                {initialEntry ? (
                    <>
                        <Check size={16} className="mr-1" />
                        Update Entry
                    </>
                ) : 'Save Entry'}
              </button>
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, BriefcaseMedical, Bot, Plus, LogOut, Download, BarChart3, Settings as SettingsIcon } from 'lucide-react';
import { Login } from './components/Login';
import { Dashboard } from './components/Dashboard';
import { PillCabinet } from './components/PillCabinet';
import { LogModal } from './components/LogModal';
import { AIAssistant } from './components/AIAssistant';
import { Reports } from './components/Reports';
import { Settings } from './components/Settings';
import { loadUserData, saveUserData, getLastSessionEmail, clearSession, deleteUserData } from './services/storage';
import { UserData, AppTab, LogEntry, Pill } from './types';

function App() {
  const [user, setUser] = useState<UserData | null>(() => {
    const lastEmail = getLastSessionEmail();
    if (lastEmail) {
      return loadUserData(lastEmail);
    }
    return null;
  });

  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [isLogModalOpen, setIsLogModalOpen] = useState(false);
  const [editingLog, setEditingLog] = useState<LogEntry | null>(null);

  // Apply Font Size Global Scaling
  useEffect(() => {
    // Default to 1.25rem if not set
    const size = user?.settings?.fontSize || '1.25rem';
    document.documentElement.style.fontSize = size;
  }, [user?.settings?.fontSize]);

  const handleLogin = (email: string) => {
    const data = loadUserData(email);
    setUser(data);
  };

  const handleLogout = () => {
    clearSession();
    setUser(null);
    setActiveTab(AppTab.DASHBOARD);
    // Reset font size on logout optionally, or keep preference. Keeping it is better UX usually.
  };

  const handleExportData = () => {
    if (!user) return;
    const dataStr = JSON.stringify(user, null, 2);
    const blob = new Blob([dataStr], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `medtrack_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Generic updater for User Data
  const updateUserData = (newData: Partial<UserData>) => {
    if (!user) return;
    const updated = { ...user, ...newData };
    setUser(updated);
    saveUserData(updated);
  };

  const handleUpdatePills = (pills: Pill[]) => {
    updateUserData({ pills });
  };

  const handleUpdateFontSize = (newSize: string) => {
    if(!user) return;
    updateUserData({ settings: { ...user.settings, fontSize: newSize } });
  };

  const handleUpdateEmail = (newEmail: string) => {
    if (!user) return;
    const oldEmail = user.email;
    const updatedUser = { ...user, email: newEmail };

    // 1. Save new data under new key
    saveUserData(updatedUser);

    // 2. Remove old data
    deleteUserData(oldEmail);

    // 3. Update State
    setUser(updatedUser);
  };

  const handleSaveLog = (entry: LogEntry) => {
    if (!user) return;

    // Create a fresh copy of the logs array
    let newLogs = [...user.logs];
    const existingIndex = newLogs.findIndex(l => l.id === entry.id);

    if (existingIndex >= 0) {
      newLogs[existingIndex] = entry; // Update existing
    } else {
      newLogs.push(entry); // Create new
    }

    updateUserData({ logs: newLogs });
  };

  const handleDeleteLog = (id: string) => {
    if (!user) return;

    // Confirm before deleting
    if (window.confirm("Are you sure you want to delete this entry?")) {
      setUser(prevUser => {
        if (!prevUser) return null;

        const newLogs = prevUser.logs.filter(l => l.id !== id);
        const updatedUser = { ...prevUser, logs: newLogs };

        // Sync to storage immediately
        saveUserData(updatedUser);

        return updatedUser;
      });

      // Close modal and clear editing state
      setIsLogModalOpen(false);
      setEditingLog(null); 
    }
  };

  const openLogModal = (entry?: LogEntry) => {
    setEditingLog(entry || null);
    setIsLogModalOpen(true);
  };

  const closeLogModal = () => {
    setIsLogModalOpen(false);
    setTimeout(() => setEditingLog(null), 300);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-100 font-sans text-slate-900 pb-24 md:pb-0">
      {/* Top Navigation */}
      <header className="bg-white shadow-sm sticky top-0 z-10 border-b border-slate-200">
        <div className="max-w-6xl mx-auto px-4 h-16 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-teal-600 rounded-lg flex items-center justify-center text-white font-bold text-lg">M</div>
            <span className="font-bold text-xl tracking-tight text-slate-800">MedTrack AI</span>
          </div>

          <div className="flex items-center space-x-2 md:space-x-4">
             <div className="hidden md:block text-sm text-slate-500 mr-2">{user.email}</div>

             <button 
                onClick={handleExportData} 
                className="text-slate-500 hover:text-teal-600 transition flex items-center gap-1 px-3 py-1 rounded-md hover:bg-slate-100"
                title="Backup Data"
             >
               <Download size={18} />
               <span className="hidden sm:inline text-sm font-medium">Backup</span>
             </button>

             <div className="h-6 w-px bg-slate-200 mx-1"></div>

